import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * WeatherCard - A reusable weather information display component.
 * 
 * Displays current weather conditions for a city including temperature,
 * condition with icon, humidity, wind speed, and a 5-day forecast strip.
 * All data comes from props - this is a pure display component.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  // Map common weather conditions to emoji icons if not provided
  const getWeatherIcon = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sunny') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloudy') || condLower.includes('cloud')) return '☁️';
    if (condLower.includes('rainy') || condLower.includes('rain')) return '🌧️';
    if (condLower.includes('snow')) return '❄️';
    if (condLower.includes('storm') || condLower.includes('thunder')) return '⛈️';
    if (condLower.includes('windy') || condLower.includes('wind')) return '💨';
    if (condLower.includes('partly')) return '⛅';
    return '🌤️'; // default weather icon
  };

  // Generate day names for forecast items without explicit days
  const getDayName = (index: number): string => {
    const days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
    const today = new Date().getDay();
    return days[(today + index) % 7];
  };

  const conditionIcon = getWeatherIcon(condition);

  return (
    <Card
      shadow="md"
      radius="lg"
      padding={24}
      border={true}
    >
      <Stack direction="vertical" gap={20}>
        {/* Header: City and Current Temperature */}
        <Stack direction="horizontal" justify="between" align="center" gap={16}>
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Location
            </Text>
            <Heading
              level={3}
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {city}
            </Heading>
          </Stack>
          <Box padding={0}>
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {temperature}°{unit}
            </Text>
          </Box>
        </Stack>

        {/* Weather Condition */}
        <Stack direction="horizontal" align="center" gap={12}>
          <Text size="3xl" as="span">
            {conditionIcon}
          </Text>
          <Text
            size="lg"
            weight="medium"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Details Grid: Humidity & Wind Speed */}
        <Stack direction="horizontal" gap={16} justify="between">
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              size="lg"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text
              size="lg"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
            </Text>
          </Stack>
        </Stack>

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin={16}
          color="var(--ggui-color-outline, #d4d4d8)"
        />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" gap={12} justify="start" wrap={false}>
          {forecast.map((item, index) => {
            const dayLabel = item.day || getDayName(index);
            const forecastIcon = item.icon || getWeatherIcon(item.high?.toString() || '');
            const highTemp = item.high !== undefined ? `${item.high}°` : '—';
            const lowTemp = item.low !== undefined ? `${item.low}°` : '—';

            return (
              <Stack
                key={`forecast-${index}`}
                direction="vertical"
                gap={8}
                align="center"
              >
                <Text
                  variant="caption"
                  weight="medium"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {dayLabel}
                </Text>
                <Text size="2xl" as="span" color="currentColor">
                  {forecastIcon}
                </Text>
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                >
                  {highTemp}
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {lowTemp}
                </Text>
              </Stack>
            );
          })}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Card,
  Heading,
  Text,
  Badge,
  Avatar,
  Button,
  Icon,
  Input,
  Select,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  columns: Array<{
    id?: string;
    name?: string;
  }>;
  onTaskUpdate?: (payload: {
    action: string;
    taskId?: string;
    data: any;
  }) => void;
}

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

function TaskCard({
  task,
  isEditing,
  editTitle,
  onEditTitleChange,
  onSaveEdit,
  onStartEdit,
  onMoveTask,
  columnId,
  columns,
}: {
  task: Task;
  isEditing: boolean;
  editTitle: string;
  onEditTitleChange: (value: string) => void;
  onSaveEdit: (taskId: string) => void;
  onStartEdit: (task: Task) => void;
  onMoveTask: (taskId: string, targetColumnId: string) => void;
  columnId: string;
  columns: Array<{ id?: string; name?: string }>;
}) {
  const taskCardRef = React.useRef<HTMLDivElement>(null);

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'low':
        return 'warning';
      default:
        return 'default';
    }
  };

  const getPriorityLabel = (priority?: string) => {
    return priority === 'high'
      ? 'HIGH'
      : priority === 'low'
        ? 'LOW'
        : 'MEDIUM';
  };

  return (
    <div
      ref={taskCardRef}
      style={{
        padding: 'var(--ggui-spacing-2, 8px)',
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        cursor: 'pointer',
        transition: 'all 200ms ease-in-out',
      }}
      onMouseEnter={() => {
        if (taskCardRef.current) {
          taskCardRef.current.style.backgroundColor =
            'var(--ggui-color-surfaceVariant, #f4f4f5)';
          taskCardRef.current.style.boxShadow =
            'var(--ggui-shape-shadow-sm, 0 1px 2px 0 rgba(0,0,0,0.05))';
        }
      }}
      onMouseLeave={() => {
        if (taskCardRef.current) {
          taskCardRef.current.style.backgroundColor =
            'var(--ggui-color-surface, #fafafa)';
          taskCardRef.current.style.boxShadow = 'none';
        }
      }}
    >
      <Stack gap={8}>
        {isEditing ? (
          <>
            <Input
              label="Edit Title"
              value={editTitle}
              onChange={onEditTitleChange}
              size="sm"
              placeholder="Task title"
            />
            <Stack direction="horizontal" gap={8}>
              <Button
                size="xs"
                variant="primary"
                onClick={() => onSaveEdit(task.id || '')}
              >
                Save
              </Button>
              <Button size="xs" variant="ghost" onClick={() => onStartEdit({} as Task)}>
                Cancel
              </Button>
            </Stack>
          </>
        ) : (
          <>
            <Text
              as="span"
              variant="bodySmall"
              weight="medium"
              truncate={true}
              color="var(--ggui-color-onSurface, #18181b)"
              style={{
                cursor: 'text',
                display: 'block',
              } as React.CSSProperties}
            >
              <span
                style={{ cursor: 'text' }}
                onClick={(e) => {
                  if (e.detail === 2 && e.button === 0) {
                    onStartEdit(task);
                  }
                }}
              >
                {task.title}
              </span>
            </Text>

            <Stack direction="horizontal" gap={8} align="center">
              <Badge
                variant={getPriorityVariant(task.priority)}
                size="sm"
                pill={true}
              >
                {getPriorityLabel(task.priority)}
              </Badge>

              {task.assignee && (
                <Avatar name={task.assignee} size="xs" shape="circle" />
              )}

              {task.dueDate && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {task.dueDate}
                </Text>
              )}
            </Stack>

            <Select
              value={columnId}
              onChange={(newColId) => onMoveTask(task.id || '', newColId)}
              options={columns
                .filter((c) => c.id !== columnId)
                .map((c) => ({
                  value: c.id || '',
                  label: `Move to ${c.name}`,
                }))}
              size="sm"
            />
          </>
        )}
      </Stack>
    </div>
  );
}

function AddTaskForm({
  taskTitle,
  taskPriority,
  formError,
  isSubmitting,
  onTitleChange,
  onPriorityChange,
  onSubmit,
  onCancel,
}: {
  taskTitle: string;
  taskPriority: 'low' | 'medium' | 'high';
  formError: string;
  isSubmitting: boolean;
  onTitleChange: (value: string) => void;
  onPriorityChange: (value: string) => void;
  onSubmit: () => void;
  onCancel: () => void;
}) {
  return (
    <Card
      padding={12}
      shadow="none"
      border={true}
      radius="md"
      style={{
        backgroundColor: 'var(--ggui-color-container, #ede9fe)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={12}>
        <Input
          label="Task Title"
          placeholder="Enter task title"
          value={taskTitle}
          onChange={onTitleChange}
          error={formError}
          size="sm"
          disabled={isSubmitting}
        />

        <Select
          label="Priority"
          value={taskPriority}
          onChange={onPriorityChange}
          options={[
            { value: 'low', label: 'Low' },
            { value: 'medium', label: 'Medium' },
            { value: 'high', label: 'High' },
          ]}
          size="sm"
          disabled={isSubmitting}
        />

        <Stack direction="horizontal" gap={8}>
          <Button
            variant="primary"
            size="sm"
            fullWidth={true}
            onClick={onSubmit}
            disabled={isSubmitting}
            loading={isSubmitting}
          >
            Add Task
          </Button>
          <Button
            variant="ghost"
            size="sm"
            fullWidth={true}
            onClick={onCancel}
            disabled={isSubmitting}
          >
            Cancel
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

export default function GeneratedComponent({
  tasks = [],
  columns = [],
  onTaskUpdate = () => {},
}: Props) {
  const [newTaskFormOpen, setNewTaskFormOpen] = useState<{
    [key: string]: boolean;
  }>({});
  const [taskTitle, setTaskTitle] = useState('');
  const [taskPriority, setTaskPriority] = useState<
    'low' | 'medium' | 'high'
  >('medium');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formError, setFormError] = useState('');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  const tasksByColumn = useMemo(() => {
    const grouped: { [key: string]: Task[] } = {};
    columns.forEach((col) => {
      grouped[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return grouped;
  }, [tasks, columns]);

  const summary = useMemo(
    () => ({
      total: tasks.length,
      completed: tasks.filter((t) => t.column === 'done').length,
      inProgress: tasks.filter((t) => t.column === 'in-progress').length,
    }),
    [tasks]
  );

  const handleAddTask = async (columnId: string) => {
    if (!taskTitle.trim()) {
      setFormError('Task title is required');
      return;
    }

    setIsSubmitting(true);
    try {
      const newTask: Task = {
        id: `task-${Date.now()}`,
        title: taskTitle.trim(),
        priority: taskPriority,
        column: columnId,
      };

      onTaskUpdate({
        action: 'create',
        taskId: newTask.id,
        data: newTask,
      });

      setTaskTitle('');
      setTaskPriority('medium');
      setFormError('');
      setNewTaskFormOpen({ ...newTaskFormOpen, [columnId]: false });
    } catch (error) {
      setFormError('Failed to add task');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleMoveTask = (taskId: string, targetColumnId: string) => {
    onTaskUpdate({
      action: 'move',
      taskId,
      data: { targetColumn: targetColumnId },
    });
  };

  const handleUpdateTask = (
    taskId: string,
    updatedFields: Partial<Task>
  ) => {
    onTaskUpdate({
      action: 'edit',
      taskId,
      data: updatedFields,
    });
  };

  const handleSaveEdit = (taskId: string) => {
    if (editTitle.trim()) {
      handleUpdateTask(taskId, { title: editTitle.trim() });
      setEditingTaskId(null);
      setEditTitle('');
    }
  };

  const handleStartEdit = (task: Task) => {
    setEditingTaskId(task.id || '');
    setEditTitle(task.title || '');
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Box
          background="var(--ggui-color-primary-50, #f0f9ff)"
          padding="16px"
          borderRadius="var(--ggui-shape-radius-md, 8px)"
          style={{
            borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)',
          }}
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Heading
              level={3}
              color="var(--ggui-color-primary-900, #0c4a6e)"
            >
              Task Board
            </Heading>
            <Stack direction="horizontal" gap={12} align="center">
              <Badge variant="primary" size="md">
                Total: {summary.total}
              </Badge>
              <Badge variant="success" size="md">
                Completed: {summary.completed}
              </Badge>
              <Badge variant="info" size="md">
                In Progress: {summary.inProgress}
              </Badge>
            </Stack>
          </Stack>
        </Box>

        <Divider orientation="horizontal" margin={8} />

        <Stack direction="horizontal" gap={16} align="start">
          {columns.map((column) => {
            const columnId = column.id || '';
            const columnTasks = tasksByColumn[columnId] || [];
            const isFormOpen = newTaskFormOpen[columnId];

            return (
              <Card
                key={columnId}
                padding={16}
                shadow="sm"
                border={true}
                radius="md"
                style={{
                  flex: 1,
                  backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  minHeight: '600px',
                  display: 'flex',
                  flexDirection: 'column',
                  borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                } as React.CSSProperties}
              >
                <Stack direction="horizontal" justify="between" align="center" gap={8}>
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text
                      variant="label"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {column.name}
                    </Text>
                    <Badge variant="default" size="sm" pill={true}>
                      {columnTasks.length}
                    </Badge>
                  </Stack>
                </Stack>

                <Divider orientation="horizontal" margin={12} />

                <Stack
                  gap={12}
                  style={{
                    flex: 1,
                    overflowY: 'auto',
                  } as React.CSSProperties}
                >
                  {columnTasks.length === 0 ? (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      align="center"
                    >
                      No tasks
                    </Text>
                  ) : (
                    columnTasks.map((task) => (
                      <TaskCard
                        key={task.id}
                        task={task}
                        isEditing={editingTaskId === task.id}
                        editTitle={editTitle}
                        onEditTitleChange={setEditTitle}
                        onSaveEdit={handleSaveEdit}
                        onStartEdit={handleStartEdit}
                        onMoveTask={handleMoveTask}
                        columnId={columnId}
                        columns={columns}
                      />
                    ))
                  )}
                </Stack>

                {!isFormOpen ? (
                  <Button
                    variant="outline"
                    size="sm"
                    fullWidth={true}
                    onClick={() => {
                      setNewTaskFormOpen({
                        ...newTaskFormOpen,
                        [columnId]: true,
                      });
                    }}
                    leftIcon={<Icon name="plus" size={16} />}
                  >
                    Add Task
                  </Button>
                ) : (
                  <AddTaskForm
                    taskTitle={taskTitle}
                    taskPriority={taskPriority}
                    formError={formError}
                    isSubmitting={isSubmitting}
                    onTitleChange={setTaskTitle}
                    onPriorityChange={(value) =>
                      setTaskPriority(value as 'low' | 'medium' | 'high')
                    }
                    onSubmit={() => handleAddTask(columnId)}
                    onCancel={() => {
                      setNewTaskFormOpen({
                        ...newTaskFormOpen,
                        [columnId]: false,
                      });
                      setTaskTitle('');
                      setTaskPriority('medium');
                      setFormError('');
                    }}
                  />
                )}
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Container,
  Stack,
  Input,
  Card,
  Text,
  Heading,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

const getCategoryColor = (category?: string): { bg: string; text: string } => {
  const categoryMap: Record<string, { bg: string; text: string }> = {
    'alkali-metal': { bg: 'var(--ggui-color-warning-50, #fffbeb)', text: 'var(--ggui-color-warning-700, #b45309)' },
    'alkaline-earth': { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-700, #b45309)' },
    'noble-gas': { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-700, #0369a1)' },
    'halogen': { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-700, #b91c1c)' },
    'transition-metal': { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', text: 'var(--ggui-color-neutral-700, #374151)' },
    'lanthanide': { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-700, #0e7490)' },
    'actinide': { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-700, #0e7490)' },
    'nonmetal': { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-700, #15803d)' },
    'metalloid': { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-neutral-800, #1f2937)' },
  };
  return categoryMap[category || 'nonmetal'] || categoryMap['nonmetal'];
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter((elem) => {
      return elem.name?.toLowerCase().includes(query) || elem.symbol?.toLowerCase().includes(query);
    });
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    const cats = new Set(elements.map((e) => e.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [elements]);

  const selectedElement = useMemo(
    () => elements.find((e) => e.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const filteredAtomicNumbers = useMemo(
    () => new Set(filteredElements.map((e) => e.atomicNumber)),
    [filteredElements]
  );

  const maxRow = Math.max(...elements.map((e) => e.row || 0), 7);
  const maxCol = Math.max(...elements.map((e) => e.col || 0), 18);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1} align="center">Periodic Table of Elements</Heading>

        <Input label="Search Elements" placeholder="Search by element name or symbol..." value={searchQuery} onChange={setSearchQuery} type="search" />

        <Stack direction="horizontal" gap={12} wrap align="center">
          {categories.map((category) => {
            const colors = getCategoryColor(category);
            return (
              <div key={category} style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)', padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)', backgroundColor: colors.bg, color: colors.text, borderRadius: 'var(--ggui-shape-radius-sm, 4px)', fontSize: 'var(--ggui-font-size-xs, 12px)', fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>
                {category.replace(/-/g, ' ')}
              </div>
            );
          })}
        </Stack>

        <div style={{ display: 'grid', gridTemplateColumns: `repeat(${maxCol}, 1fr)`, gridTemplateRows: `repeat(${maxRow}, auto)`, gap: 'var(--ggui-spacing-1, 4px)', backgroundColor: 'var(--ggui-color-surface, #fafafa)', padding: 'var(--ggui-spacing-2, 8px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
          {elements.map((element) => {
            const { atomicNumber = 0, symbol = '', name = '', category = 'nonmetal', row = 1, col = 1 } = element;
            const colors = getCategoryColor(category);
            const isVisible = filteredAtomicNumbers.has(atomicNumber);
            const isSelected = selectedAtomicNumber === atomicNumber;

            return (
              <button key={atomicNumber} onClick={() => setSelectedAtomicNumber(atomicNumber)} onKeyDown={(e: React.KeyboardEvent<HTMLButtonElement>) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setSelectedAtomicNumber(atomicNumber); } else if (e.key === 'Escape') { setSelectedAtomicNumber(null); } }} style={{ gridRow: row, gridColumn: col, backgroundColor: isVisible ? colors.bg : 'transparent', color: colors.text, border: `1px solid ${isVisible ? 'var(--ggui-color-outline, #d4d4d8)' : 'transparent'}`, borderRadius: 'var(--ggui-shape-radius-md, 8px)', padding: 'var(--ggui-spacing-2, 8px)', cursor: isVisible ? 'pointer' : 'default', opacity: isVisible ? 1 : 0.3, boxShadow: isSelected ? '0 0 0 3px var(--ggui-color-primary-600, #0284c7)' : 'none', transition: 'all 200ms ease-in-out', minHeight: '80px', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', alignItems: 'center', textAlign: 'center', fontFamily: 'inherit', fontSize: 'var(--ggui-font-size-base, 16px)' }} role="button" tabIndex={isVisible ? 0 : -1} aria-label={`${name} (${symbol}), atomic number ${atomicNumber}`} aria-pressed={isSelected}>
                <span style={{ alignSelf: 'flex-start', fontSize: 'var(--ggui-font-size-xs, 12px)', lineHeight: '1' }}>{atomicNumber}</span>
                <span style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', lineHeight: '1' }}>{symbol}</span>
                {name && <span style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', opacity: 0.7, lineHeight: '1' }}>{name}</span>}
              </button>
            );
          })}
        </div>

        {selectedElement && (
          <Card shadow="md" radius="lg" padding={20}>
            <Stack gap={16}>
              <Stack gap={8} align="center">
                <Heading level={3} align="center">{selectedElement.name || 'Unknown Element'}</Heading>
                <div style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', textAlign: 'center', color: 'var(--ggui-color-onSurface, #18181b)' }}>{selectedElement.symbol}</div>
              </Stack>

              <Divider orientation="horizontal" margin={8} />

              <Stack direction="horizontal" gap={24} justify="around">
                <Stack gap={4} align="start">
                  <Text variant="label" size="sm">Atomic Number</Text>
                  <Text variant="body">{selectedElement.atomicNumber}</Text>
                </Stack>
                <Stack gap={4} align="start">
                  <Text variant="label" size="sm">Atomic Weight</Text>
                  <Text variant="body">{selectedElement.atomicWeight || 'N/A'}</Text>
                </Stack>
                <Stack gap={4} align="start">
                  <Text variant="label" size="sm">Category</Text>
                  <Badge variant="primary">{selectedElement.category?.replace(/-/g, ' ')}</Badge>
                </Stack>
              </Stack>

              <Divider orientation="horizontal" margin={8} />

              <Text variant="caption" align="center" color="var(--ggui-color-neutral-500, #6b7280)">
                Click another element to view details, or press Escape to close.
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Card, Stack, Input, Button, Text, Heading, Badge, Box, Divider } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

interface MessageGroup {
  sender?: string;
  messages: Message[];
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages = [], onSendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const messageListRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, [messages]);

  const messageGroups = useMemo((): MessageGroup[] => {
    const groups: MessageGroup[] = [];
    for (const message of messages) {
      if (groups.length === 0 || groups[groups.length - 1].sender !== message.sender) {
        groups.push({ sender: message.sender, messages: [message] });
      } else {
        groups[groups.length - 1].messages.push(message);
      }
    }
    return groups;
  }, [messages]);

  const handleSend = () => {
    const trimmedText = inputValue.trim();
    if (!trimmedText) return;

    onSendMessage?.({
      text: trimmedText,
      timestamp: new Date().toISOString(),
    });

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTimestamp = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return timestamp;
    }
  };

  const isCurrentUserMessage = (sender?: string): boolean => {
    return sender === currentUser;
  };

  return (
    <Card
      shadow="md"
      border={true}
      radius="lg"
      padding={16}
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        maxHeight: '600px',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        gap={16}
        style={{ marginBottom: 'var(--ggui-spacing-2, 8px)' }}
      >
        <Heading
          level={4}
          color="var(--ggui-color-onSurface, #18181b)"
          style={{ margin: 0 }}
        >
          {title}
        </Heading>
        {participantCount !== undefined && (
          <Badge variant="primary" size="sm" pill={true}>
            {participantCount} {participantCount === 1 ? 'participant' : 'participants'}
          </Badge>
        )}
      </Stack>

      <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

      <div
        ref={messageListRef}
        style={{
          flex: 1,
          overflowY: 'auto',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-4, 16px)',
          marginBottom: 'var(--ggui-spacing-4, 16px)',
          paddingRight: 'var(--ggui-spacing-2, 8px)',
        }}
        role="log"
        aria-live="polite"
      >
        {messageGroups.length === 0 ? (
          <Box
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              flex: 1,
            }}
          >
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No messages yet. Start a conversation!
            </Text>
          </Box>
        ) : (
          messageGroups.map((group, groupIdx) => {
            const isOwn = isCurrentUserMessage(group.sender);
            return (
              <Stack
                key={groupIdx}
                direction="vertical"
                gap={4}
                align={isOwn ? 'end' : 'start'}
              >
                {group.sender && (
                  <Text
                    variant="label"
                    size="sm"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {group.sender}
                  </Text>
                )}

                {group.messages.map((msg, msgIdx) => (
                  <Stack
                    key={msgIdx}
                    direction="vertical"
                    gap={2}
                    align={isOwn ? 'end' : 'start'}
                  >
                    <Box
                      padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      background={
                        isOwn
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      style={{
                        maxWidth: '70%',
                        wordWrap: 'break-word',
                        overflowWrap: 'break-word',
                      }}
                    >
                      <Text
                        variant="body"
                        color={isOwn ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                        as="span"
                      >
                        {msg.text}
                      </Text>
                    </Box>

                    {msg.timestamp && (
                      <Text
                        variant="caption"
                        size="xs"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{
                          paddingInline: isOwn ? 'var(--ggui-spacing-2, 8px)' : '0',
                        }}
                      >
                        {formatTimestamp(msg.timestamp)}
                      </Text>
                    )}
                  </Stack>
                ))}
              </Stack>
            );
          })
        )}
      </div>

      <Stack direction="horizontal" gap={8} align="end">
        <Box style={{ flex: 1 }}>
          <Input label="Message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} onKeyDown={handleKeyDown} size="md" />
        </Box>
        <Button variant="primary" size="md" onClick={handleSend} disabled={!inputValue.trim()}>
          Send
        </Button>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Heading, Container, Box, Spinner } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTicker(props: Props) {
  const { stocks = [], lastUpdated } = props;
  const [displayedStocks, setDisplayedStocks] = useState<Stock[]>(stocks);
  const [isConnected, setIsConnected] = useState(true);

  // Update displayed stocks when props change
  useEffect(() => {
    setDisplayedStocks(stocks);
    if (stocks.length > 0) {
      setIsConnected(true);
    }
  }, [stocks]);

  const formatPrice = (price?: number): string => {
    if (price === undefined) return '—';
    return `$${price.toFixed(2)}`;
  };

  const formatChange = (change?: number): string => {
    if (change === undefined) return '—';
    return change >= 0 ? `+${change.toFixed(2)}` : `${change.toFixed(2)}`;
  };

  const getChangeColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    return change >= 0
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';
  };

  const getChangeBorderColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-outline, #d4d4d8)';
    return change >= 0
      ? 'var(--ggui-color-success-200, #bbf7d0)'
      : 'var(--ggui-color-error-200, #fecaca)';
  };

  const getArrowIcon = (change?: number): string => {
    if (change === undefined) return '—';
    return change >= 0 ? '▲' : '▼';
  };

  const formatLastUpdated = (timestamp?: string): string => {
    if (!timestamp) return 'No updates yet';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch {
      return 'Invalid timestamp';
    }
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={8}>
          <Heading level={1}>Market Watch</Heading>
          <Text
            variant="bodySmall"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Last Updated: {formatLastUpdated(lastUpdated)}
          </Text>
        </Stack>

        {/* Stock Grid */}
        {displayedStocks.length > 0 && (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            } as React.CSSProperties}
          >
            {displayedStocks.map((stock) => (
              <Card
                key={stock.symbol || 'unknown'}
                padding={20}
                shadow="md"
                border={true}
                radius="lg"
                style={{
                  borderColor: getChangeBorderColor(stock.change),
                  borderWidth: '2px',
                  transition: 'all 200ms ease-in-out',
                }}
              >
                <Stack gap={16}>
                  {/* Ticker Symbol */}
                  <Heading
                    level={3}
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {stock.symbol || '—'}
                  </Heading>

                  {/* Company Name */}
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {stock.name || 'Unknown'}
                  </Text>

                  {/* Price */}
                  <Stack direction="horizontal" gap={12} align="center">
                    <Text
                      variant="bodyLarge"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {formatPrice(stock.price)}
                    </Text>
                  </Stack>

                  {/* Change and Change Percent */}
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text
                      variant="body"
                      color={getChangeColor(stock.change)}
                      weight="semibold"
                    >
                      {formatChange(stock.change)}
                    </Text>
                    <Box
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 'var(--ggui-spacing-1, 4px)',
                      }}
                    >
                      <Text
                        variant="body"
                        color={getChangeColor(stock.changePercent)}
                        weight="semibold"
                        as="span"
                      >
                        {getArrowIcon(stock.changePercent)}
                      </Text>
                      <Text
                        variant="body"
                        color={getChangeColor(stock.changePercent)}
                        weight="semibold"
                        as="span"
                      >
                        {stock.changePercent !== undefined
                          ? `${Math.abs(stock.changePercent).toFixed(2)}%`
                          : '—'}
                      </Text>
                    </Box>
                  </Stack>
                </Stack>
              </Card>
            ))}
          </div>
        )}

        {/* Empty State */}
        {displayedStocks.length === 0 && (
          <Card padding={32} shadow="sm" radius="lg">
            <Stack gap={12} align="center">
              <Spinner size={24} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Connecting to live data...
              </Text>
              <Text
                variant="bodySmall"
                color="var(--ggui-color-outline, #d4d4d8)"
              >
                Stock data will appear here once loaded
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Input,
  Select,
  Button,
  Badge,
  Progress,
  Toggle,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (profileData: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

type SelectOption = {
  value: string;
  label: string;
};

export default function OnboardingWizard({
  initialProfile = {},
  avatarOptions,
  roleOptions,
  onComplete,
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(initialProfile.name || '');
  const [email, setEmail] = useState(initialProfile.email || '');
  const [avatar, setAvatar] = useState(initialProfile.avatar || '');
  const [role, setRole] = useState(initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState(initialProfile.theme || 'light');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [roleError, setRoleError] = useState('');

  const validateEmail = (emailValue: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(emailValue);
  };

  const validateStep1 = (): boolean => {
    let isValid = true;
    setNameError('');
    setEmailError('');

    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    }

    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    }

    if (!avatar) {
      isValid = false;
    }

    return isValid;
  };

  const validateStep2 = (): boolean => {
    setRoleError('');
    if (!role) {
      setRoleError('Role is required');
      return false;
    }
    return true;
  };

  const handleNext = () => {
    if (currentStep === 1 && validateStep1()) {
      setCurrentStep(2);
    } else if (currentStep === 2 && validateStep2()) {
      setCurrentStep(3);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = () => {
    if (onComplete) {
      onComplete({
        name,
        email,
        avatar,
        role,
        emailNotifications,
        theme,
      });
    }
  };

  const isStep1Valid = name.trim() && validateEmail(email) && avatar;
  const isStep2Valid = role;

  const roleSelectOptions: SelectOption[] = roleOptions.map((roleName) => ({
    value: roleName.toLowerCase().replace(/\s+/g, '_'),
    label: roleName,
  }));

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24} direction="vertical">
        {/* Step Indicator with Progress Bar */}
        <Stack gap={16} direction="vertical" align="stretch">
          <Progress
            value={currentStep}
            max={3}
            variant="default"
            size="md"
            showLabel={false}
          />

          {/* Step Circles */}
          <Stack gap={16} direction="horizontal" align="center" justify="center">
            {[1, 2, 3].map((step) => (
              <div
                key={step}
                style={{
                  width: '40px',
                  height: '40px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  borderRadius: '9999px',
                  backgroundColor:
                    step <= currentStep
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-neutral-200, #e5e7eb)',
                  color:
                    step <= currentStep
                      ? 'white'
                      : 'var(--ggui-color-neutral-700, #374151)',
                  fontSize: 'var(--ggui-font-size-sm, 14px)',
                  fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                  transition: 'all 200ms ease-in-out',
                  cursor: 'pointer',
                }}
                aria-current={currentStep === step ? 'step' : undefined}
                aria-label={`Step ${step} of 3`}
              >
                {step < currentStep ? '✓' : step}
              </div>
            ))}
          </Stack>
        </Stack>

        {/* Content Card */}
        <Card shadow="md" padding={24} border={true} radius="lg">
          {/* Step 1: Profile Setup */}
          {currentStep === 1 && (
            <Stack gap={20} direction="vertical">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Create Your Profile
              </Heading>

              <Input
                label="Full Name"
                required={true}
                type="text"
                placeholder="John Doe"
                value={name}
                onChange={setName}
                error={nameError}
              />

              <Input
                label="Email Address"
                required={true}
                type="email"
                placeholder="you@example.com"
                value={email}
                onChange={setEmail}
                error={emailError}
              />

              {/* Avatar Selection */}
              <Stack gap={12} direction="vertical">
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurface, #18181b)"
                  as="label"
                >
                  Avatar <span style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
                </Text>
                <Stack gap={12} direction="horizontal" wrap={true} align="stretch">
                  {avatarOptions.map((emojiOption, idx) => (
                    <button
                      key={idx}
                      onClick={() => setAvatar(emojiOption)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.preventDefault();
                          setAvatar(emojiOption);
                        }
                      }}
                      style={{
                        width: 'calc(var(--ggui-spacing-6, 24px) * 3.5)',
                        height: 'calc(var(--ggui-spacing-6, 24px) * 3.5)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        border:
                          avatar === emojiOption
                            ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                            : '2px solid var(--ggui-color-outline, #d4d4d8)',
                        cursor: 'pointer',
                        fontSize: '36px',
                        transition: 'all 200ms ease-in-out',
                        boxShadow:
                          avatar === emojiOption
                            ? 'inset 0 0 0 4px var(--ggui-color-primary-100, #e0f2fe)'
                            : 'none',
                        backgroundColor: 'transparent',
                        padding: 0,
                        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      }}
                      aria-pressed={avatar === emojiOption}
                      type="button"
                      aria-label={`Select avatar ${emojiOption}`}
                    >
                      {emojiOption}
                    </button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {/* Step 2: Preferences */}
          {currentStep === 2 && (
            <Stack gap={20} direction="vertical">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Set Your Preferences
              </Heading>

              <Select
                label="Role"
                required={true}
                value={role}
                onChange={setRole}
                options={roleSelectOptions}
                placeholder="Select your role"
                error={roleError}
              />

              {/* Email Notifications Toggle */}
              <Stack gap={8} direction="vertical">
                <Toggle
                  label="Email Notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="span"
                >
                  Receive updates and announcements via email
                </Text>
              </Stack>

              {/* Theme Toggle */}
              <Stack gap={8} direction="vertical">
                <Toggle
                  label="Dark Mode"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="span"
                >
                  Switch between light and dark interface
                </Text>
              </Stack>
            </Stack>
          )}

          {/* Step 3: Review & Confirm */}
          {currentStep === 3 && (
            <Stack gap={20} direction="vertical">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Review & Confirm
              </Heading>

              {/* Summary Box */}
              <Box
                padding={16}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius={8}
              >
                <Stack gap={12} direction="vertical">
                  {/* Name */}
                  <Stack gap={0} direction="horizontal" justify="between" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      Name
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" as="span">
                      {name}
                    </Text>
                  </Stack>

                  <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

                  {/* Email */}
                  <Stack gap={0} direction="horizontal" justify="between" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      Email
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" as="span">
                      {email}
                    </Text>
                  </Stack>

                  <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

                  {/* Avatar */}
                  <Stack gap={0} direction="horizontal" justify="between" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      Avatar
                    </Text>
                    <Text
                      variant="body"
                      color="var(--ggui-color-onSurface, #18181b)"
                      as="span"
                      style={{ fontSize: '24px' }}
                    >
                      {avatar}
                    </Text>
                  </Stack>

                  <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

                  {/* Role */}
                  <Stack gap={0} direction="horizontal" justify="between" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      Role
                    </Text>
                    <Badge variant="primary">{role}</Badge>
                  </Stack>

                  <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

                  {/* Email Notifications */}
                  <Stack gap={0} direction="horizontal" justify="between" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      Email Notifications
                    </Text>
                    <Badge variant={emailNotifications ? 'success' : 'default'}>
                      {emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Stack>

                  <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

                  {/* Theme */}
                  <Stack gap={0} direction="horizontal" justify="between" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      Theme
                    </Text>
                    <Badge variant="primary">
                      {theme === 'dark' ? 'Dark Mode' : 'Light Mode'}
                    </Badge>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          )}
        </Card>

        {/* Navigation Buttons */}
        <Stack gap={12} direction="horizontal" justify="end" align="center">
          {currentStep > 1 && (
            <Button variant="secondary" size="md" onClick={handleBack}>
              Go Back
            </Button>
          )}

          {currentStep < 3 && (
            <Button
              variant="primary"
              size="md"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid)
              }
            >
              Next
            </Button>
          )}

          {currentStep === 3 && (
            <Button variant="primary" size="md" onClick={handleComplete}>
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard(props: Props): React.ReactNode {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = '°C',
    forecast,
  } = props;

  /**
   * Map weather condition to emoji for visual representation
   */
  const getWeatherEmoji = (cond: string): string => {
    const lower = cond.toLowerCase();
    if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
    if (lower.includes('cloud')) return '☁️';
    if (lower.includes('rain')) return '🌧️';
    if (lower.includes('snow')) return '❄️';
    if (lower.includes('wind')) return '💨';
    if (lower.includes('fog')) return '🌫️';
    if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
    return '🌤️';
  };

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={16}>
        {/* Header: City and Condition Emoji */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3} color="var(--ggui-color-onSurface, #111827)">
            {city}
          </Heading>
          <Text as="span" size="2xl">
            {getWeatherEmoji(condition)}
          </Text>
        </Stack>

        {/* Current Temperature Display - Large and Prominent */}
        <Stack gap={8} align="center">
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
            align="center"
          >
            {temperature}{unit}
          </Text>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="center"
          >
            {condition}
          </Text>
        </Stack>

        {/* Humidity and Wind Speed */}
        <Stack direction="horizontal" gap={16} justify="between">
          <Box>
            <Stack gap={4} align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                size="lg"
                weight="medium"
                color="var(--ggui-color-onSurface, #111827)"
              >
                {humidity}%
              </Text>
            </Stack>
          </Box>
          <Box>
            <Stack gap={4} align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind Speed
              </Text>
              <Text
                size="lg"
                weight="medium"
                color="var(--ggui-color-onSurface, #111827)"
              >
                {windSpeed} km/h
              </Text>
            </Stack>
          </Box>
        </Stack>

        {/* Visual Divider */}
        <Divider margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

        {/* 5-Day Forecast Strip */}
        <Stack gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            5-Day Forecast
          </Text>
          <Stack direction="horizontal" gap={8} wrap>
            {forecast.map((day, index) => (
              <Box
                key={index}
                padding={12}
                borderRadius={8}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              >
                <Stack gap={6} align="center">
                  {/* Day name */}
                  <Text
                    variant="caption"
                    weight="medium"
                    color="var(--ggui-color-onSurface, #111827)"
                    align="center"
                  >
                    {day.day || `Day ${index + 1}`}
                  </Text>
                  {/* Weather icon/emoji */}
                  <Text as="span" size="lg">
                    {day.icon || getWeatherEmoji(condition)}
                  </Text>
                  {/* High/Low temperatures */}
                  <Stack direction="horizontal" gap={4} justify="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-primary-600, #0284c7)"
                    >
                      {day.high}{unit}
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {day.low}{unit}
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = '',
  temperature = 0,
  condition = '',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const normalizedUnit = unit ?? 'C';

  const getConditionIcon = (value?: string): string => {
    const normalized = (value || '').toLowerCase();
    if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) return '❄️';
    if (normalized.includes('mist') || normalized.includes('fog') || normalized.includes('haze')) return '🌫️';
    if (normalized.includes('wind')) return '💨';
    return '🌤️';
  };

  const safeTemperature = Number.isFinite(temperature) ? temperature : null;
  const safeHumidity = Number.isFinite(humidity) ? humidity : null;
  const safeWindSpeed = Number.isFinite(windSpeed) ? windSpeed : null;

  const displayedForecast = forecast.slice(0, 5);

  return (
    <Card
      shadow="md"
      radius="lg"
      border={true}
      padding="var(--ggui-spacing-6, 24px)"
      role="region"
      aria-label={`Weather for ${city || 'selected city'}`}
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Text
              variant="overline"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              City
            </Text>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
              {city || '—'}
            </Heading>
          </Stack>

          <Text
            variant="bodySmall"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="right"
          >
            {condition || '—'}
          </Text>
        </Stack>

        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap={4}>
            <Text
              as="span"
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {safeTemperature !== null ? `${safeTemperature}°${normalizedUnit}` : '—'}
            </Text>
          </Stack>

          <Text
            as="span"
            size="4xl"
            color="var(--ggui-color-primary-600, #0284c7)"
            aria-label={condition || 'Weather condition icon'}
          >
            {getConditionIcon(condition)}
          </Text>
        </Stack>

        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-md, 8px)"
        >
          <Stack
            direction="horizontal"
            justify="between"
            wrap={true}
            gap="var(--ggui-spacing-4, 16px)"
          >
            <Stack gap={2}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {safeHumidity !== null ? `${safeHumidity}%` : '—'}
              </Text>
            </Stack>

            <Stack gap={2}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {safeWindSpeed !== null ? `${safeWindSpeed}` : '—'}
              </Text>
            </Stack>
          </Stack>
        </Box>

        <Divider
          orientation="horizontal"
          margin="var(--ggui-spacing-2, 8px)"
          color="var(--ggui-color-outlineVariant, #e4e4e7)"
        />

        <Stack gap="var(--ggui-spacing-2, 8px)" role="list" aria-label="5-day forecast">
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            5-Day Forecast
          </Text>

          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap={false}>
            {displayedForecast.map((item, index) => {
              const day = item.day || '—';
              const icon = item.icon || getConditionIcon(condition);
              const hasHigh = typeof item.high === 'number' && Number.isFinite(item.high);
              const hasLow = typeof item.low === 'number' && Number.isFinite(item.low);
              const tempRange =
                hasHigh || hasLow
                  ? `${hasHigh ? `${item.high}°` : '—'}/${hasLow ? `${item.low}°` : '—'}`
                  : '—';

              return (
                <Box
                  key={`${item.day || 'day'}-${index}`}
                  role="listitem"
                  padding="var(--ggui-spacing-2, 8px)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  margin={0}
                  style={{
                    flex: '1 1 0',
                    minWidth: 0,
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={2} align="center">
                    <Text
                      variant="caption"
                      truncate
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      align="center"
                    >
                      {day}
                    </Text>
                    <Text
                      as="span"
                      size="xl"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-label={`${day} weather icon`}
                    >
                      {icon || '—'}
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      align="center"
                    >
                      {tempRange}
                    </Text>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  onSubmit?: (payload: { title: string; priority: 'low' | 'medium' | 'high' }) => Promise<unknown> | unknown;
}

type BoardTask = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

export default function GeneratedComponent({
  tasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ],
  taskUpdate = () => undefined,
  onSubmit,
}: Props) {
  const safeColumns = columns.map((c, idx) => ({
    id: c.id || `column-${idx + 1}`,
    name: c.name || `Column ${idx + 1}`,
  }));

  const [boardTasks, setBoardTasks] = useState<BoardTask[]>(
    tasks.map((t, idx) => ({
      id: t.id || `task-${idx + 1}`,
      title: t.title || `Untitled Task ${idx + 1}`,
      priority: t.priority || 'low',
      assignee: t.assignee || 'NA',
      column: t.column || safeColumns[0]?.id || 'todo',
      dueDate: t.dueDate,
    }))
  );

  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTitle, setNewTitle] = useState<string>('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newError, setNewError] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  const totalTasks = boardTasks.length;
  const completedCount = boardTasks.filter((t) => t.column === 'done').length;

  const priorityVariant = (p: 'low' | 'medium' | 'high') =>
    p === 'low' ? 'success' : p === 'medium' ? 'warning' : 'error';

  const moveOptions = useMemo(
    () => safeColumns.map((c) => ({ value: c.id, label: c.name })),
    [safeColumns]
  );

  const updateTask = (taskId: string, action: string, data: Record<string, unknown>) => {
    taskUpdate({ action, taskId, data });
  };

  const handleMove = (taskId: string, nextColumn: string) => {
    setBoardTasks((prev) =>
      prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task))
    );
    updateTask(taskId, 'move', { column: nextColumn });
  };

  const startEdit = (task: BoardTask) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
  };

  const saveEdit = (taskId: string) => {
    if (!editingTitle.trim()) return;
    setBoardTasks((prev) =>
      prev.map((task) => (task.id === taskId ? { ...task, title: editingTitle.trim() } : task))
    );
    updateTask(taskId, 'edit', { title: editingTitle.trim() });
    setEditingTaskId('');
    setEditingTitle('');
  };

  const submitNewTask = async () => {
    setNewError('');
    setFeedback(null);

    if (!newTitle.trim()) {
      setNewError('Task title is required.');
      return;
    }

    setIsSubmitting(true);
    try {
      if (onSubmit) {
        await onSubmit({ title: newTitle.trim(), priority: newPriority });
      }

      const createdTask: BoardTask = {
        id: `task-${Date.now()}`,
        title: newTitle.trim(),
        priority: newPriority,
        assignee: 'NA',
        column: safeColumns[0]?.id || 'todo',
      };

      setBoardTasks((prev) => [...prev, createdTask]);
      updateTask(createdTask.id, 'create', createdTask);
      setFeedback({ type: 'success', text: 'Task created successfully.' });
      setNewTitle('');
      setNewPriority('medium');
      setAddingColumnId('');
    } catch {
      setFeedback({ type: 'error', text: 'Failed to create task. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Stack gap={16}>
      <Card
        padding={16}
        shadow="sm"
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack direction="horizontal" justify="between" align="center">
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Total Tasks: {totalTasks}
          </Text>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Completed: {completedCount}
          </Text>
        </Stack>
      </Card>

      {feedback ? (
        <Alert variant={feedback.type === 'success' ? 'success' : 'error'} title="Status">
          {feedback.text}
        </Alert>
      ) : null}

      <Stack direction="horizontal" gap={12} align="start" wrap>
        {safeColumns.map((column) => {
          const columnTasks = boardTasks.filter((task) => task.column === column.id);
          return (
            <Card
              key={column.id}
              padding={12}
              shadow="sm"
              style={{
                minWidth: 300,
                flex: 1,
                background: 'var(--ggui-color-surface, #fafafa)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={10}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {column.name}
                  </Text>
                  <Badge variant="default" size="sm">
                    {columnTasks.length}
                  </Badge>
                </Stack>

                <Stack gap={8}>
                  {columnTasks.map((task) => (
                    <Card
                      key={task.id}
                      padding={10}
                      shadow="none"
                      style={{
                        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                      }}
                    >
                      <Stack gap={8}>
                        <Stack direction="horizontal" justify="between" align="center">
                          {editingTaskId === task.id ? (
                            <Input
                              label="Edit title"
                              value={editingTitle}
                              onChange={setEditingTitle}
                              size="sm"
                              required
                              aria-label={`Edit title for ${task.title}`}
                            />
                          ) : (
                            <Text
                              variant="bodySmall"
                              weight="medium"
                              color="var(--ggui-color-onSurface, #18181b)"
                            >
                              {task.title}
                            </Text>
                          )}

                          <Stack direction="horizontal" gap={6}>
                            {editingTaskId === task.id ? (
                              <Button size="xs" variant="primary" onClick={() => saveEdit(task.id)}>
                                Save
                              </Button>
                            ) : (
                              <Button size="xs" variant="ghost" onClick={() => startEdit(task)}>
                                Edit
                              </Button>
                            )}
                          </Stack>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={priorityVariant(task.priority)} size="sm">
                            {task.priority}
                          </Badge>

                          <Stack direction="horizontal" gap={6} align="center">
                            <Avatar name={task.assignee} size="xs" />
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              {task.assignee}
                            </Text>
                          </Stack>
                        </Stack>

                        {task.dueDate ? (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Due: {task.dueDate}
                          </Text>
                        ) : null}

                        <Select
                          label="Move to"
                          value={task.column}
                          onChange={(value) => handleMove(task.id, value)}
                          options={moveOptions}
                          size="sm"
                          aria-label={`Move ${task.title}`}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingColumnId === column.id ? (
                  <Card
                    padding={10}
                    shadow="none"
                    style={{
                      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                    }}
                  >
                    <Stack gap={8}>
                      <Input
                        label="Task title"
                        value={newTitle}
                        onChange={setNewTitle}
                        required
                        error={newError}
                        placeholder="Enter task title"
                      />
                      <Select
                        label="Priority"
                        value={newPriority}
                        onChange={(value) => setNewPriority(value as 'low' | 'medium' | 'high')}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Stack direction="horizontal" gap={8}>
                        <Button
                          variant="primary"
                          size="sm"
                          onClick={submitNewTask}
                          loading={isSubmitting}
                          disabled={isSubmitting}
                        >
                          Submit
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => {
                            setAddingColumnId('');
                            setNewError('');
                          }}
                          disabled={isSubmitting}
                        >
                          Cancel
                        </Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button
                    variant="outline"
                    size="sm"
                    fullWidth
                    onClick={() => {
                      setAddingColumnId(column.id);
                      setFeedback(null);
                    }}
                  >
                    Add Task
                  </Button>
                )}
              </Stack>
            </Card>
          );
        })}
      </Stack>
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(undefined);

  const categoryColorMap: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
    'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
    'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
    'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
    metalloid: 'var(--ggui-color-success-500, #22c55e)',
    nonmetal: 'var(--ggui-color-primary-600, #0284c7)',
    halogen: 'var(--ggui-color-warning-600, #d97706)',
    'noble gas': 'var(--ggui-color-success-600, #16a34a)',
    lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
    actinide: 'var(--ggui-color-error-600, #dc2626)',
    unknown: 'var(--ggui-color-neutral-500, #6b7280)',
  };

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return undefined;
    return elements.find((el) => el.atomicNumber === selectedAtomicNumber);
  }, [elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      set.add((el.category ?? 'unknown').toLowerCase());
    });
    return Array.from(set);
  }, [elements]);

  return (
    <Card
      padding={16}
      border
      shadow="sm"
      radius="lg"
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table
        </Text>

        <Input
          label="Search elements"
          type="search"
          placeholder="Search by name or symbol"
          value={query}
          onChange={setQuery}
          aria-label="Search elements by name or symbol"
        />

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
        >
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
            aria-label="Periodic table grid"
            role="grid"
          >
            {filteredElements.map((el) => {
              const categoryKey = (el.category ?? 'unknown').toLowerCase();
              const borderColor =
                categoryColorMap[categoryKey] ?? 'var(--ggui-color-neutral-500, #6b7280)';

              return (
                <Button
                  key={`${el.atomicNumber ?? 'unknown'}-${el.symbol ?? 'el'}`}
                  variant="ghost"
                  size="sm"
                  onPress={() => setSelectedAtomicNumber(el.atomicNumber)}
                  aria-label={`Select ${el.name ?? 'element'} (${el.symbol ?? ''})`}
                  style={{
                    gridColumn: `${el.col ?? 1}`,
                    gridRow: `${el.row ?? 1}`,
                    minHeight: 56,
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid ${borderColor}`,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background:
                      selectedAtomicNumber === el.atomicNumber
                        ? 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                        : 'var(--ggui-color-surface, #fafafa)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    position: 'relative',
                    transition: 'background-color 200ms ease, transform 100ms ease',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: '2px',
                      left: '4px',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    }}
                  >
                    {el.atomicNumber ?? '—'}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-lg, 18px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      lineHeight: 1,
                    }}
                  >
                    {el.symbol ?? '—'}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card padding={12} border shadow="none" radius="md">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body"><strong>Name:</strong> {selectedElement.name ?? '—'}</Text>
                <Text variant="body"><strong>Symbol:</strong> {selectedElement.symbol ?? '—'}</Text>
                <Text variant="body"><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}</Text>
                <Text variant="body"><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}</Text>
                <Text variant="body"><strong>Category:</strong> {selectedElement.category ?? '—'}</Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to see details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card padding={12} border shadow="none" radius="md">
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((cat) => {
                const color = categoryColorMap[cat] ?? 'var(--ggui-color-neutral-500, #6b7280)';
                return (
                  <Stack key={cat} direction="horizontal" align="center" gap={6}>
                    <span
                      aria-hidden="true"
                      style={{
                        width: 12,
                        height: 12,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: color,
                        border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {cat}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message — Called when user sends a message. Payload: { text, timestamp } */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type ChatMessage = { sender?: string; text?: string; timestamp?: string };

export default function GeneratedComponent(props: Props) {
  const {
    title = '',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
  } = props;

  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<ChatMessage[]>([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: ChatMessage[] }> = [];
    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTimestamp = (iso?: string) => {
    if (!iso) return '';
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<ChatMessage | ChatMessage[]>;
      const detail = customEvent.detail;
      if (!detail) return;

      const incoming = Array.isArray(detail) ? detail : [detail];
      setStreamMessages((prev) => [...prev, ...incoming]);
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const canSend = draft.trim().length > 0;

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setDraft('');
  };

  return (
    <Card
      padding={0}
      shadow="md"
      border
      radius="lg"
    >
      <Stack
        gap={0}
      >
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          gap="var(--ggui-spacing-2, 8px)"
        >
          <Stack
            direction="horizontal"
            justify="between"
            align="center"
            gap="var(--ggui-spacing-2, 8px)"
            style={{
              width: '100%',
              padding: 'var(--ggui-spacing-4, 16px)',
              borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
              as="div"
            >
              {title}
            </Text>
            {typeof participantCount === 'number' && (
              <Badge variant="primary" size="sm">
                {participantCount}
              </Badge>
            )}
          </Stack>
        </Stack>

        <Stack
          gap="var(--ggui-spacing-2, 8px)"
          style={{
            height: '360px',
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          ref={listRef}
          aria-label="Chat messages"
          role="log"
          aria-live="polite"
        >
          {groupedMessages.map((group, groupIndex) => {
            const isCurrentUser = (group.sender ?? '') === currentUser;
            return (
              <Stack
                key={`${group.sender ?? 'unknown'}-${groupIndex}`}
                gap="var(--ggui-spacing-1, 4px)"
                align={isCurrentUser ? 'end' : 'start'}
              >
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="span"
                >
                  {group.sender || ''}
                </Text>

                {group.items.map((msg, msgIndex) => (
                  <Stack
                    key={`${msg.timestamp ?? 'no-time'}-${msgIndex}`}
                    gap="var(--ggui-spacing-1, 4px)"
                    align={isCurrentUser ? 'end' : 'start'}
                    style={{
                      maxWidth: '80%',
                    }}
                  >
                    <Card
                      padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                      shadow="none"
                      border={false}
                      radius="lg"
                    >
                      <Text
                        variant="bodySmall"
                        color={
                          isCurrentUser
                            ? 'var(--ggui-color-onContainer, #4c1d95)'
                            : 'var(--ggui-color-onSurface, #18181b)'
                        }
                        as="div"
                      >
                        {msg.text || ''}
                      </Text>
                    </Card>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      {formatTimestamp(msg.timestamp)}
                    </Text>
                  </Stack>
                ))}
              </Stack>
            );
          })}
        </Stack>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          }}
        >
          <Stack style={{ flex: 1 }}>
            <Input
              label=""
              placeholder="Type a message"
              value={draft}
              onChange={setDraft}
              aria-label="Message input"
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </Stack>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!canSend}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const detail = customEvent.detail;

      if (detail?.stocks) {
        setLiveStocks(detail.stocks);
      }
      if (typeof detail?.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', onAgentData as EventListener);
    const connectTimer = window.setTimeout(() => setIsConnecting(false), 1800);

    return () => {
      window.removeEventListener('ggui:agent-data', onAgentData as EventListener);
      window.clearTimeout(connectTimer);
    };
  }, []);

  const formattedUpdatedTime = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  const hasStocks = liveStocks.length > 0;

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      radius="lg"
      shadow="sm"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
      aria-label="Market watch stock ticker dashboard"
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Text
            as="div"
            size="3xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>
          <Stack gap={4} align="end">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Last Updated
            </Text>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {formattedUpdatedTime}
            </Text>
          </Stack>
        </Stack>

        {isConnecting && (
          <Card
            padding="var(--ggui-spacing-4, 16px)"
            radius="md"
            border
            shadow="none"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
            role="status"
            aria-live="polite"
          >
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Spinner size={18} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Connecting to live market feed...
              </Text>
            </Stack>
          </Card>
        )}

        {!isConnecting && !hasStocks && (
          <Card
            padding="var(--ggui-spacing-4, 16px)"
            radius="md"
            border
            shadow="none"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
            role="status"
            aria-live="polite"
          >
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Waiting for stock data...
            </Text>
          </Card>
        )}

        {hasStocks && (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {liveStocks.map((stock, index) => {
              const symbol = stock.symbol ?? '—';
              const name = stock.name ?? 'Unknown Company';
              const price = typeof stock.price === 'number' ? stock.price : 0;
              const change = typeof stock.change === 'number' ? stock.change : 0;
              const changePercent = typeof stock.changePercent === 'number' ? stock.changePercent : 0;

              const isPositive = change >= 0;
              const trendArrow = isPositive ? '▲' : '▼';
              const trendColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';

              return (
                <Card
                  key={`${symbol}-${name}-${index}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  radius="lg"
                  shadow="sm"
                  border
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: trendColor,
                    transition:
                      'transform var(--ggui-duration-normal, 200ms) var(--ggui-easing-easeOut, ease), box-shadow var(--ggui-duration-normal, 200ms) var(--ggui-easing-easeOut, ease)',
                  }}
                  aria-label={`${symbol} stock card`}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {symbol}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {name}
                    </Text>
                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${price.toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text
                        variant="label"
                        color={trendColor}
                        aria-label={`Change amount ${change >= 0 ? '+' : ''}${change.toFixed(2)}`}
                      >
                        {change >= 0 ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text
                        variant="label"
                        color={trendColor}
                        aria-label={`Change percentage ${changePercent >= 0 ? '+' : ''}${changePercent.toFixed(2)} percent`}
                      >
                        {trendArrow} {changePercent >= 0 ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(
    props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? ''
  );
  const [role, setRole] = useState(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState(props.initialProfile?.theme ?? 'light');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean; role: boolean }>({
    name: false,
    email: false,
    role: false,
  });

  const titles = {
    heading: 'Onboarding Wizard',
    step1: 'Profile Setup',
    step2: 'Preferences',
    step3: 'Review & Confirm',
    name: 'Name',
    email: 'Email',
    avatar: 'Choose an Avatar',
    role: 'Role',
    notif: 'Email Notifications',
    theme: 'Theme Preference',
    back: 'Back',
    next: 'Next',
    goBack: 'Go Back',
    complete: 'Complete Setup',
  };

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const step1Valid = name.trim().length > 0 && emailValid && !!avatar;
  const step2Valid = role.trim().length > 0;
  const nextDisabled = (step === 1 && !step1Valid) || (step === 2 && !step2Valid);

  const progressValue = (step / 3) * 100;

  const handleNext = () => {
    if (step === 1) {
      setTouched((t) => ({ ...t, name: true, email: true }));
      if (!step1Valid) return;
    }
    if (step === 2) {
      setTouched((t) => ({ ...t, role: true }));
      if (!step2Valid) return;
    }
    setStep((s) => Math.min(3, s + 1));
  };

  const handleBack = () => setStep((s) => Math.max(1, s - 1));

  const handleComplete = () => {
    const payload = { name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme };
    props.complete?.(payload);
  };

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailValid
      ? 'Enter a valid email address.'
      : '';
  const roleError = touched.role && !role ? 'Role is required.' : '';

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <MotionKeyframes />
      <Stack gap={20}>
        <Stack gap={8}>
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {titles.heading}
          </Text>
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} / 3
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {step === 1 ? titles.step1 : step === 2 ? titles.step2 : titles.step3}
            </Text>
          </Stack>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        <Card
          padding={16}
          shadow="none"
          border
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            transition: motionEnabled ? 'all 200ms ease' : 'none',
          }}
          aria-live="polite"
        >
          {step === 1 && (
            <Stack gap={14}>
              <Text variant="label">{titles.step1}</Text>
              <Input
                label={titles.name}
                value={name}
                onChange={setName}
                required
                placeholder="Enter your full name"
                error={nameError || undefined}
                onBlur={() => setTouched((t) => ({ ...t, name: true }))}
              />
              <Input
                label={titles.email}
                type="email"
                value={email}
                onChange={setEmail}
                required
                placeholder="you@example.com"
                error={emailError || undefined}
                onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              />
              <Stack gap={8}>
                <Text variant="label">{titles.avatar}</Text>
                <Stack direction="horizontal" gap={8} wrap>
                  {props.avatarOptions.map((item) => {
                    const selected = avatar === item;
                    return (
                      <Button
                        key={item}
                        variant={selected ? 'primary' : 'outline'}
                        size="md"
                        onClick={() => setAvatar(item)}
                        aria-label={`Select avatar ${item}`}
                      >
                        {item}
                      </Button>
                    );
                  })}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={14}>
              <Text variant="label">{titles.step2}</Text>
              <Select
                label={titles.role}
                value={role}
                onChange={setRole}
                placeholder="Select your role"
                required
                error={roleError || undefined}
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                onBlur={() => setTouched((t) => ({ ...t, role: true }))}
              />
              <Toggle
                label={titles.notif}
                checked={emailNotifications}
                onChange={setEmailNotifications}
              />
              <Toggle
                label={`${titles.theme}: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                checked={theme === 'dark'}
                onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={12}>
              <Text variant="label">{titles.step3}</Text>
              <Card padding={12} border radius="md" shadow="none">
                <Stack gap={8}>
                  <Text variant="bodySmall"><strong>Name:</strong> {name || '-'}</Text>
                  <Text variant="bodySmall"><strong>Email:</strong> {email || '-'}</Text>
                  <Text variant="bodySmall"><strong>Avatar:</strong> {avatar || '-'}</Text>
                  <Text variant="bodySmall"><strong>Role:</strong> {role || '-'}</Text>
                  <Text variant="bodySmall">
                    <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                  </Text>
                  <Text variant="bodySmall"><strong>Theme:</strong> {theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Card>

        <Stack direction="horizontal" justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
            aria-label={step === 3 ? titles.goBack : titles.back}
          >
            {step === 3 ? titles.goBack : titles.back}
          </Button>

          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={nextDisabled} aria-label={titles.next}>
              {titles.next}
            </Button>
          ) : (
            <Button variant="primary" onClick={handleComplete} aria-label={titles.complete}>
              {titles.complete}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Container,
  Stack,
  Card,
  Heading,
  Text,
  Badge,
  Avatar,
  Button,
  Input,
  Select,
  Divider,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;

  /** Action Contract callback (wired) */
  taskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId?: string; data: Record<string, unknown> }) => Promise<void> | void;
}

const defaultColumns: Array<{ id?: string; name?: string }> = [
  { id: 'todo', name: 'To Do' },
  { id: 'in-progress', name: 'In Progress' },
  { id: 'done', name: 'Done' },
];

export default function GeneratedComponent({
  tasks = [],
  columns = defaultColumns,
  taskUpdate = async () => {},
}: Props) {
  const [localTasks, setLocalTasks] = useState<Props['tasks']>(tasks);

  const [activeAddColumnId, setActiveAddColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [submitSuccess, setSubmitSuccess] = useState<string | null>(null);

  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [isUpdatingTaskId, setIsUpdatingTaskId] = useState<string | null>(null);
  const [updateErrorByTaskId, setUpdateErrorByTaskId] = useState<Record<string, string>>({});
  const [updateSuccessByTaskId, setUpdateSuccessByTaskId] = useState<Record<string, string>>({});

  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  const todoColumnId = useMemo(() => {
    const todoById = columns.find((c) => (c.id || '').toLowerCase() === 'todo');
    if (todoById?.id) return todoById.id;
    return columns[0]?.id || 'todo';
  }, [columns]);

  const doneColumnId = useMemo(() => {
    const doneById = columns.find((c) => (c.id || '').toLowerCase() === 'done');
    const doneByName = columns.find((c) => (c.name || '').toLowerCase() === 'done');
    return doneById?.id || doneByName?.id || 'done';
  }, [columns]);

  const totalTasks = localTasks.length;
  const completedCount = localTasks.filter((t) => t.column === doneColumnId).length;

  const priorityOptions = [
    { value: 'low', label: 'Low' },
    { value: 'medium', label: 'Medium' },
    { value: 'high', label: 'High' },
  ];

  const getPriorityVariant = (priority?: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error' as const;
    if (priority === 'medium') return 'warning' as const;
    return 'success' as const;
  };

  const startEdit = (taskId: string, currentTitle?: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle || '');
    setUpdateErrorByTaskId((prev) => ({ ...prev, [taskId]: '' }));
    setUpdateSuccessByTaskId((prev) => ({ ...prev, [taskId]: '' }));
  };

  const cancelEdit = () => {
    setEditingTaskId(null);
    setEditingTitle('');
  };

  const saveEdit = async (taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) {
      setUpdateErrorByTaskId((prev) => ({ ...prev, [taskId]: 'Title is required.' }));
      return;
    }
    if (trimmed.length > 120) {
      setUpdateErrorByTaskId((prev) => ({ ...prev, [taskId]: 'Title must be 120 characters or fewer.' }));
      return;
    }

    const prevTasks = localTasks;
    setIsUpdatingTaskId(taskId);
    setUpdateErrorByTaskId((prev) => ({ ...prev, [taskId]: '' }));

    setLocalTasks((curr) => curr.map((t) => (t.id === taskId ? { ...t, title: trimmed } : t)));

    try {
      await taskUpdate({ action: 'edit', taskId, data: { title: trimmed } });
      setUpdateSuccessByTaskId((prev) => ({ ...prev, [taskId]: 'Task updated.' }));
      setEditingTaskId(null);
      setEditingTitle('');
    } catch {
      setLocalTasks(prevTasks);
      setUpdateErrorByTaskId((prev) => ({ ...prev, [taskId]: 'Failed to update task. Please retry.' }));
    } finally {
      setIsUpdatingTaskId(null);
    }
  };

  const moveTask = async (taskId: string, toColumnId: string) => {
    const existing = localTasks.find((t) => t.id === taskId);
    if (!existing) return;
    const fromColumnId = existing.column;
    if (fromColumnId === toColumnId) return;

    const prevTasks = localTasks;
    setIsUpdatingTaskId(taskId);
    setUpdateErrorByTaskId((prev) => ({ ...prev, [taskId]: '' }));
    setUpdateSuccessByTaskId((prev) => ({ ...prev, [taskId]: '' }));

    setLocalTasks((curr) => curr.map((t) => (t.id === taskId ? { ...t, column: toColumnId } : t)));

    try {
      await taskUpdate({ action: 'move', taskId, data: { column: toColumnId } });
      setUpdateSuccessByTaskId((prev) => ({ ...prev, [taskId]: 'Task moved.' }));
    } catch {
      setLocalTasks(prevTasks);
      setUpdateErrorByTaskId((prev) => ({ ...prev, [taskId]: 'Failed to move task. Reverted.' }));
    } finally {
      setIsUpdatingTaskId(null);
    }
  };

  const addTitleError = !newTaskTitle.trim() ? 'Title is required.' : newTaskTitle.trim().length > 120 ? 'Title must be 120 characters or fewer.' : '';
  const addPriorityError = ['low', 'medium', 'high'].includes(newTaskPriority) ? '' : 'Priority is invalid.';
  const addDisabled = Boolean(addTitleError || addPriorityError || isSubmitting);

  const submitAddTask = async () => {
    setSubmitError(null);
    setSubmitSuccess(null);

    const trimmed = newTaskTitle.trim();
    if (!trimmed) {
      setSubmitError('Please enter a task title.');
      return;
    }
    if (trimmed.length > 120) {
      setSubmitError('Task title must be 120 characters or fewer.');
      return;
    }
    if (!['low', 'medium', 'high'].includes(newTaskPriority)) {
      setSubmitError('Please select a valid priority.');
      return;
    }

    const newId = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const newTask = {
      id: newId,
      title: trimmed,
      priority: newTaskPriority,
      assignee: '',
      column: todoColumnId,
    };

    const prevTasks = localTasks;
    setIsSubmitting(true);
    setLocalTasks((curr) => [newTask, ...curr]);

    try {
      await taskUpdate({ action: 'create', taskId: newId, data: newTask as Record<string, unknown> });
      setSubmitSuccess('Task created successfully.');
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setActiveAddColumnId(null);
    } catch {
      setLocalTasks(prevTasks);
      setSubmitError('Failed to create task. Please retry.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Card
          shadow="sm"
          radius="lg"
          padding="var(--ggui-spacing-4, 16px)"
          border
        >
          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Stack gap={4}>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">Kanban Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Track progress across your workflow
              </Text>
            </Stack>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Total: {totalTasks}</Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Completed: {completedCount}</Text>
            </Stack>
          </Stack>
        </Card>

        <Divider color="var(--ggui-color-outline, #d4d4d8)" margin={0} />

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-4, 16px)"
          align="start"
          wrap
        >
          {columns.map((column, columnIndex) => {
            const columnId = column.id || `column-${columnIndex}`;
            const columnName = column.name || 'Untitled';
            const tasksInColumn = localTasks.filter((task) => task.column === columnId);
            const columnHeadingId = `column-heading-${columnId}`;
            const isTodoColumn = columnId === todoColumnId;

            return (
              <Card
                key={columnId}
                shadow="sm"
                radius="lg"
                padding="var(--ggui-spacing-4, 16px)"
                border
              >
                <div
                  role="region"
                  aria-labelledby={columnHeadingId}
                  aria-label="Kanban task board"
                  style={{
                    minWidth: '280px',
                    flex: 1,
                    background: 'var(--ggui-color-surface, #fafafa)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-3, 12px)">
                    <Stack direction="horizontal" justify="between" align="center">
                      <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">
                        <span id={columnHeadingId}>{columnName}</span>
                      </Heading>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {tasksInColumn.length}
                      </Text>
                    </Stack>

                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      {tasksInColumn.map((task, taskIndex) => {
                        const taskId = task.id || `${columnId}-task-${taskIndex}`;
                        const taskTitle = task.title || 'Untitled task';
                        const isEditing = editingTaskId === taskId;
                        const isUpdating = isUpdatingTaskId === taskId;

                        return (
                          <Card
                            key={taskId}
                            shadow="sm"
                            radius="md"
                            padding="var(--ggui-spacing-3, 12px)"
                            border
                          >
                            <Stack gap="var(--ggui-spacing-2, 8px)">
                              {isEditing ? (
                                <Stack gap="var(--ggui-spacing-2, 8px)">
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    error={updateErrorByTaskId[taskId]}
                                    placeholder="Enter task title"
                                    disabled={isUpdating}
                                    onKeyDown={(e) => {
                                      if (e.key === 'Enter' && !isUpdating) {
                                        saveEdit(taskId);
                                      }
                                      if (e.key === 'Escape') {
                                        cancelEdit();
                                      }
                                    }}
                                  />
                                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
                                    <Button
                                      variant="primary"
                                      size="sm"
                                      onClick={() => saveEdit(taskId)}
                                      loading={isUpdating}
                                      disabled={isUpdating}
                                      aria-label={`Save task ${taskTitle}`}
                                    >
                                      Save
                                    </Button>
                                    <Button
                                      variant="ghost"
                                      size="sm"
                                      onClick={cancelEdit}
                                      disabled={isUpdating}
                                      aria-label={`Cancel editing ${taskTitle}`}
                                    >
                                      Cancel
                                    </Button>
                                  </Stack>
                                </Stack>
                              ) : (
                                <Stack direction="horizontal" justify="between" align="start" wrap>
                                  <Text
                                    variant="label"
                                    color="var(--ggui-color-onSurface, #18181b)"
                                    as="div"
                                  >
                                    <span onDoubleClick={() => startEdit(taskId, task.title)}>{taskTitle}</span>
                                  </Text>
                                  <Button
                                    variant="outline"
                                    size="xs"
                                    onClick={() => startEdit(taskId, task.title)}
                                    aria-label={`Edit task ${taskTitle}`}
                                  >
                                    Edit
                                  </Button>
                                </Stack>
                              )}

                              <Stack direction="horizontal" justify="between" align="center" wrap>
                                <Badge variant={getPriorityVariant(task.priority)} size="sm">
                                  {(task.priority || 'low').toUpperCase()}
                                </Badge>
                                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                                  <Avatar
                                    name={task.assignee || 'Unassigned'}
                                    size="sm"
                                  />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                    {task.assignee || 'Unassigned'}
                                  </Text>
                                </Stack>
                              </Stack>

                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  Due: {task.dueDate}
                                </Text>
                              ) : null}

                              <Select
                                label="Move to"
                                value={task.column || ''}
                                onChange={(value) => moveTask(taskId, value)}
                                options={columns.map((c, i) => ({
                                  value: c.id || `col-${i}`,
                                  label: c.name || `Column ${i + 1}`,
                                }))}
                                disabled={isUpdating}
                                aria-label={`Move task ${taskTitle}`}
                              />

                              {updateSuccessByTaskId[taskId] ? (
                                <Alert variant="success" title="Success">
                                  {updateSuccessByTaskId[taskId]}
                                </Alert>
                              ) : null}
                              {updateErrorByTaskId[taskId] ? (
                                <Alert variant="error" title="Error">
                                  {updateErrorByTaskId[taskId]}
                                </Alert>
                              ) : null}
                            </Stack>
                          </Card>
                        );
                      })}
                    </Stack>

                    <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

                    {activeAddColumnId === columnId ? (
                      <Card
                        shadow="none"
                        radius="md"
                        border
                        padding="var(--ggui-spacing-3, 12px)"
                      >
                        <Stack gap="var(--ggui-spacing-2, 8px)">
                          {!isTodoColumn ? (
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              New tasks are created in To Do by default.
                            </Text>
                          ) : null}

                          <Input
                            label="Task title"
                            value={newTaskTitle}
                            onChange={setNewTaskTitle}
                            placeholder="Enter task title"
                            required
                            error={submitError && !newTaskTitle.trim() ? 'Title is required.' : ''}
                            disabled={isSubmitting}
                            onKeyDown={(e) => {
                              if (e.key === 'Enter' && !addDisabled) {
                                submitAddTask();
                              }
                            }}
                          />
                          <Select
                            label="Priority"
                            value={newTaskPriority}
                            onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')}
                            options={priorityOptions}
                            required
                            disabled={isSubmitting}
                          />
                          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
                            <Button
                              variant="primary"
                              size="sm"
                              onClick={submitAddTask}
                              loading={isSubmitting}
                              disabled={addDisabled}
                            >
                              Submit
                            </Button>
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => {
                                setActiveAddColumnId(null);
                                setSubmitError(null);
                                setSubmitSuccess(null);
                              }}
                              disabled={isSubmitting}
                            >
                              Cancel
                            </Button>
                          </Stack>

                          {submitSuccess ? (
                            <Alert variant="success" title="Task Created">
                              {submitSuccess}
                            </Alert>
                          ) : null}
                          {submitError ? (
                            <Alert variant="error" title="Create Failed">
                              {submitError}
                            </Alert>
                          ) : null}
                        </Stack>
                      </Card>
                    ) : (
                      <Button
                        variant="outline"
                        size="sm"
                        fullWidth
                        onClick={() => {
                          setActiveAddColumnId(columnId);
                          setSubmitError(null);
                          setSubmitSuccess(null);
                        }}
                      >
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </div>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Box,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (category?: string): string => {
  const normalized = (category ?? '').trim().toLowerCase();
  const map: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
    'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
    'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
    'post-transition metal': 'var(--ggui-color-primary-300, #7dd3fc)',
    metalloid: 'var(--ggui-color-info-500, #06b6d4)',
    nonmetal: 'var(--ggui-color-success-500, #22c55e)',
    halogen: 'var(--ggui-color-warning-600, #d97706)',
    'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
    lanthanide: 'var(--ggui-color-success-600, #16a34a)',
    actinide: 'var(--ggui-color-error-600, #dc2626)',
  };

  return map[normalized] ?? 'var(--ggui-color-neutral-300, #d1d5db)';
};

const toTitleCase = (value?: string): string => {
  if (!value) return '—';
  return value
    .split(' ')
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ');
};

export default function GeneratedComponent({ elements = [] }: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedQuery = useMemo(() => query.trim().toLowerCase(), [query]);

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((element) => {
      const name = element.name?.toLowerCase() ?? '';
      const symbol = element.symbol?.toLowerCase() ?? '';
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement = useMemo(
    () => elements.find((element) => element.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const categories = useMemo(
    () =>
      Array.from(new Set(elements.map((e) => e.category).filter((c): c is string => Boolean(c)))),
    [elements]
  );

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const exists = elements.some((element) => element.atomicNumber === selectedAtomicNumber);
    if (!exists) setSelectedAtomicNumber(null);
  }, [elements, selectedAtomicNumber]);

  return (
    <Container
      maxWidth="full"
      padding="var(--ggui-spacing-6, 24px)"
    >
      <Stack gap={24}>
        <Stack gap={16}>
          <Heading
            level={2}
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Periodic Table
          </Heading>
          <Input
            label="Search elements"
