                  selectedAtomicNumber !== null && atomicNumber === selectedAtomicNumber;
                const categoryColor = getCategoryColor(category);

                return (
                  <Card
                    key={`${atomicNumber ?? 'unknown'}-${symbol}-${index}`}
                    padding={6}
                    border
