                      role="button"
                      tabIndex={0}
                      aria-pressed={isSelected}
                      aria-label={`${name}, symbol ${symbol}, atomic number ${atomicNumber ?? '—'}, category ${category}`}
                      onClick={() => setSelectedAtomicNumber(atomicNumber ?? null)}
                      onKeyDown={(event) => {
