import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Badge,
  Box,
  Button,
  Card,
  Divider,
  Heading,
  Input,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type Message = { sender?: string; text?: string; timestamp?: string };
type MessageGroup = { sender?: string; items: Message[] };

export default function GeneratedComponent({
  title = '',
  currentUser = '',
  participantCount = undefined,
  messages = [],
  sendMessage = undefined,
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [liveMessages, setLiveMessages] = useState<Props['messages']>(messages);
  const listRef = useRef<HTMLDivElement | null>(null);

  const inputPlaceholder = 'Type a message…';

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    setLiveMessages(messages);
  }, [messages]);

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [liveMessages]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<unknown>;
      const detail = customEvent?.detail as Partial<Message> | undefined;

      if (!detail || typeof detail !== 'object') return;

      const normalizedText = typeof detail.text === 'string' ? detail.text : '';
      if (!normalizedText.trim()) return;

      const normalizedMessage: Message = {
        sender: typeof detail.sender === 'string' ? detail.sender : undefined,
        text: normalizedText,
        timestamp:
          typeof detail.timestamp === 'string' && detail.timestamp
            ? detail.timestamp
            : new Date().toISOString(),
      };

      setLiveMessages((prev) => [...prev, normalizedMessage]);
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData);
    };
  }, []);

  const groupedMessages = useMemo<MessageGroup[]>(() => {
    return liveMessages.reduce<MessageGroup[]>((acc, msg) => {
      const last = acc[acc.length - 1];
      if (!last || last.sender !== msg.sender) {
        acc.push({ sender: msg.sender, items: [msg] });
      } else {
        last.items.push(msg);
      }
      return acc;
    }, []);
  }, [liveMessages]);

  const formatTimestamp = (value?: string) => {
    if (!value) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;

    const timestamp = new Date().toISOString();
    const payload = { text, timestamp };

    sendMessage?.(payload);
    setLiveMessages((prev) => [...prev, { sender: currentUser, text, timestamp }]);
    setDraft('');
  };

  const handleKeyDown: React.KeyboardEventHandler<HTMLInputElement> = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card
      padding={0}
      radius="lg"
      shadow="sm"
      border={true}
    >
      <Stack
        gap={0}
        style={{
          height: '100%',
          background: 'var(--ggui-color-surface, #fafafa)',
          color: 'var(--ggui-color-onSurface, #18181b)',
        }}
        role="region"
        aria-label={title || 'Chat'}
      >
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          gap="var(--ggui-spacing-2, 8px)"
          style={{ padding: 'var(--ggui-spacing-4, 16px)' }}
        >
          <Box
            style={{
              minWidth: 0,
              flex: 1,
              overflow: 'hidden',
            }}
          >
            <Heading
              level={5}
              color="var(--ggui-color-onSurface, #18181b)"
              style={{
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
            >
              {title}
            </Heading>
          </Box>

          {typeof participantCount === 'number' ? (
            <Badge variant="primary" size="sm" pill={true}>
              {participantCount}
            </Badge>
          ) : null}
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Box
          ref={listRef}
          role="log"
          aria-live="polite"
          aria-relevant="additions text"
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          <Stack gap="var(--ggui-spacing-2, 8px)">
            {groupedMessages.map((group, groupIndex) => {
              const isCurrentUserGroup = group.sender === currentUser;
              return (
                <Stack
                  key={`${group.sender ?? 'unknown'}-${groupIndex}`}
                  gap="var(--ggui-spacing-1, 4px)"
                  style={{
                    alignSelf: isCurrentUserGroup ? 'flex-end' : 'flex-start',
                    maxWidth: '80%',
                  }}
                >
                  {!isCurrentUserGroup && group.sender ? (
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {group.sender}
                    </Text>
                  ) : null}

                  {group.items.map((item, itemIndex) => {
                    const isCurrentUserMessage = item.sender === currentUser;
                    const ts = formatTimestamp(item.timestamp);

                    return (
                      <Box
                        key={`${item.sender ?? 'unknown'}-${item.timestamp ?? 'no-time'}-${itemIndex}`}
                        style={{
                          background: isCurrentUserMessage
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                          color: isCurrentUserMessage
                            ? 'var(--ggui-color-surface, #fafafa)'
                            : 'var(--ggui-color-onSurface, #18181b)',
                          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                          border: `1px solid ${
                            isCurrentUserMessage
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-outlineVariant, #e4e4e7)'
                          }`,
                          transition: 'background-color 200ms ease-in-out, opacity 200ms ease-in-out',
                        }}
                      >
                        <Stack gap="var(--ggui-spacing-1, 4px)">
                          <Text
                            variant="bodySmall"
                            color={
                              isCurrentUserMessage
                                ? 'var(--ggui-color-surface, #fafafa)'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                          >
                            {item.text || ''}
                          </Text>
                          {ts ? (
                            <Text
                              variant="caption"
                              color={
                                isCurrentUserMessage
                                  ? 'var(--ggui-color-surface, #fafafa)'
                                  : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                              }
                            >
                              {ts}
                            </Text>
                          ) : null}
                        </Stack>
                      </Box>
                    );
                  })}
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Stack
          direction="horizontal"
          align="end"
          gap="var(--ggui-spacing-2, 8px)"
          style={{ padding: 'var(--ggui-spacing-4, 16px)' }}
        >
          <Box style={{ flex: 1 }}>
            <Input
              value={draft}
              onChange={setDraft}
              size="md"
              placeholder={inputPlaceholder}
              aria-label="Message input"
              onKeyDown={handleKeyDown}
            />
          </Box>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={draft.trim().length === 0}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Box,
  Card,
  Container,
  Heading,
  Spinner,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const [displayedStocks, setDisplayedStocks] = useState<Props['stocks']>(stocks);
  const [displayedLastUpdated, setDisplayedLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [streamStatus, setStreamStatus] = useState<'connecting' | 'live' | 'stale'>('connecting');
  const [lastEventAt, setLastEventAt] = useState<number | null>(null);
  const [isDesktop, setIsDesktop] = useState<boolean>(
    typeof window !== 'undefined' ? window.innerWidth >= 1024 : false
  );

  useEffect(() => {
    setDisplayedStocks(stocks);
    if (stocks.length > 0) {
      setIsConnecting(false);
      setIsLoading(false);
      if (streamStatus === 'connecting') setStreamStatus('live');
    }
  }, [stocks, streamStatus]);

  useEffect(() => {
    setDisplayedLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    const handleResize = () => {
      setIsDesktop(window.innerWidth >= 1024);
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
      }>;
      const detail = customEvent?.detail;

      if (!detail || typeof detail !== 'object') return;

      if (Array.isArray(detail.stocks)) {
        setDisplayedStocks(detail.stocks);
      }
      if (typeof detail.lastUpdated === 'string') {
        setDisplayedLastUpdated(detail.lastUpdated);
      }

      setIsConnecting(false);
      setIsLoading(false);
      setStreamStatus('live');
      setLastEventAt(Date.now());
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  useEffect(() => {
    const interval = window.setInterval(() => {
      if (lastEventAt && Date.now() - lastEventAt > 15000 && streamStatus === 'live') {
        setStreamStatus('stale');
      }
    }, 1000);

    return () => {
      window.clearInterval(interval);
    };
  }, [lastEventAt, streamStatus]);

  const formattedLastUpdated = useMemo(() => {
    if (!displayedLastUpdated) return '—';
    const date = new Date(displayedLastUpdated);
    if (Number.isNaN(date.getTime())) return displayedLastUpdated;
    return date.toLocaleString();
  }, [displayedLastUpdated]);

  return (
    <section
      aria-label="Market Watch stock dashboard"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-2, 8px)',
      }}
    >
      <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>

            <Stack gap={4} aria-live="polite">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formattedLastUpdated}
              </Text>
              {streamStatus === 'live' && (
                <Text variant="caption" color="var(--ggui-color-success-600, #16a34a)">
                  Live
                </Text>
              )}
              {streamStatus === 'stale' && (
                <Text variant="caption" color="var(--ggui-color-warning-600, #d97706)">
                  Feed delayed
                </Text>
              )}
            </Stack>
          </Stack>

          {(isConnecting || isLoading) && (
            <Box>
              <Alert variant="info" title="Live Feed Status">
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                  <Spinner size={22} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" aria-live="polite">
                    Connecting to live market feed…
                  </Text>
                </Stack>
              </Alert>
            </Box>
          )}

          {streamStatus === 'stale' && (
            <Box>
              <Alert variant="warning" title="Feed Status">
                <Text variant="bodySmall">Feed delayed. Showing latest available prices.</Text>
              </Alert>
            </Box>
          )}

          <Box
            role="list"
            style={{
              display: 'grid',
              gap: 'var(--ggui-spacing-4, 16px)',
              gridTemplateColumns: isDesktop ? 'repeat(3, minmax(0, 1fr))' : '1fr',
            }}
          >
            {displayedStocks.map((stock, index) => {
              const safeSymbol = stock.symbol ?? '—';
              const safeName = stock.name ?? 'Unknown Company';
              const safePrice = Number.isFinite(stock.price) ? (stock.price as number) : 0;
              const safeChange = Number.isFinite(stock.change) ? (stock.change as number) : 0;
              const safeChangePercent = Number.isFinite(stock.changePercent) ? (stock.changePercent as number) : 0;
              const isPositive = safeChangePercent >= 0;
              const trendArrow = isPositive ? '▲' : '▼';
              const trendColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';

              const priceText = safePrice.toFixed(2);
              const changeText = `${safeChange >= 0 ? '+' : ''}${safeChange.toFixed(2)}`;
              const changePercentText = `${safeChangePercent >= 0 ? '+' : ''}${safeChangePercent.toFixed(2)}%`;

              return (
                <Card
                  key={stock.symbol || `${index}`}
                  padding={16}
                  radius="lg"
                  shadow="sm"
                  border
                  role="listitem"
                  aria-label={`${safeSymbol} ${safeName}, price ${priceText}, change ${changeText}, ${changePercentText} percent`}
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: trendColor,
                    transition: 'border-color 200ms ease-in-out, color 200ms ease-in-out',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      variant="body"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {safeSymbol}
                    </Text>

                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {safeName}
                    </Text>

                    <Text
                      variant="bodyLarge"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${priceText}
                    </Text>

                    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                      <Text variant="label" color={trendColor} style={{ transition: 'color 200ms ease-in-out' }}>
                        {changeText}
                      </Text>
                      <Text variant="label" color={trendColor} style={{ transition: 'color 200ms ease-in-out' }}>
                        {trendArrow} {changePercentText}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        </Stack>
      </Container>
      <Text as="span" style={{ display: 'none' }}>
        __GGUI_META__{{"category":"dashboard","description":"Reusable stock ticker dashboard with responsive card grid, trend-coded cards, and live updates via ggui:agent-data stream with connecting/live/stale states."}}
      </Text>
    </section>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {
    name: '',
    email: '',
    avatar: '',
    role: '',
    emailNotifications: true,
    theme: 'light',
  },
  avatarOptions = ['😀', '🚀', '🎨', '🧠'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  onComplete,
}: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    initialProfile.avatar ?? avatarOptions[0] ?? ''
  );
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);
  const progressValue = (step / 3) * 100;

  const handleNext = () => {
    if (step < 3 && canNext) setStep((s) => s + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleComplete = () => {
    onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          color: 'var(--ggui-color-onSurface, #18181b)',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          <Box
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={name.trim().length === 0 ? 'Name is required.' : undefined}
                  aria-label="Name"
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={
                    email.trim().length === 0
                      ? 'Email is required.'
                      : !emailValid
                      ? 'Please enter a valid email address.'
                      : undefined
                  }
                  aria-label="Email"
                />

                <Stack gap={8}>
                  <Text as="label" variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {avatarOptions.map((emoji) => (
                      <Button
                        key={emoji}
                        variant={avatar === emoji ? 'primary' : 'outline'}
                        size="md"
                        onClick={() => setAvatar(emoji)}
                        aria-label={`Select avatar ${emoji}`}
                      >
                        {emoji}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                  error={role.trim().length === 0 ? 'Role is required.' : undefined}
                  required
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>
                <Card
                  padding={16}
                  shadow="none"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                    <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                    <Text variant="body"><strong>Avatar:</strong> {avatar || '-'}</Text>
                    <Text variant="body"><strong>Role:</strong> {role || '-'}</Text>
                    <Text variant="body">
                      <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between" gap={12}>
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>

            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canNext}>
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="outline" onClick={handleBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * Displays current weather details and a 5-day forecast.
 *
 * Uses GGUI primitives for a consistent, themeable layout.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '⛅', high: 70, low: 60 },
    { day: 'Wed', icon: '☁️', high: 68, low: 58 },
    { day: 'Thu', icon: '🌧️', high: 65, low: 55 },
    { day: 'Fri', icon: '☀️', high: 74, low: 63 },
  ],
}: Props) {
  // Simple internal mapping for condition strings to default emojis if data is just a string
  const conditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('partly')) return '⛅';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('storm')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '⛅';
  };

  return (
    <Card 
      shadow="md" 
      padding={24} 
      radius="xl"
      border={true}
    >
      <Stack gap={24}>
        {/* Header Section: City and Condition Summary */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text 
              variant="label" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>
          <Box 
            paddingX={10} 
            paddingY={4} 
            background="var(--ggui-color-primary-100, #e0f2fe)" 
            borderRadius="var(--ggui-shape-radius-full, 9999px)"
          >
            <Text 
              variant="overline" 
              color="var(--ggui-color-primary-800, #075985)"
            >
              UNIT: °{unit}
            </Text>
          </Box>
        </Stack>

        {/* Hero Section: Prominent Temperature and Main Emoji */}
        <Stack direction="horizontal" align="center" gap={32}>
          <Text 
            weight="bold" 
            color="var(--ggui-color-onSurface, #18181b)"
            style={{ fontSize: 'var(--ggui-font-size-4xl, 48px)', lineHeight: 1 }}
          >
            {Math.round(temperature)}°
          </Text>
          <Text 
            style={{ fontSize: 'var(--ggui-font-size-4xl, 48px)' }}
            aria-hidden="true"
          >
            {conditionEmoji(condition)}
          </Text>
        </Stack>

        {/* Details Row: Humidity and Wind Speed */}
        <Stack direction="horizontal" gap={32}>
          <Stack gap={4}>
            <Text 
              variant="caption" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="semibold"
            >
              HUMIDITY
            </Text>
            <Text variant="bodyLarge" weight="medium">
              {humidity}%
            </Text>
          </Stack>

          <Divider orientation="vertical" margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

          <Stack gap={4}>
            <Text 
              variant="caption" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="semibold"
            >
              WIND SPEED
            </Text>
            <Text variant="bodyLarge" weight="medium">
              {windSpeed} <Text as="span" variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">km/h</Text>
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Footer Strip */}
        <Stack gap={16}>
          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Stack direction="horizontal" justify="between" align="center" gap={12}>
            {forecast.map((item, index) => (
              <Stack 
                key={`${item.day}-${index}`} 
                align="center" 
                gap={8}
                style={{ flex: 1, minWidth: '60px' }}
              >
                <Text 
                  variant="overline" 
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  {item.day}
                </Text>

                <Text size="lg" aria-hidden="true">
                  {item.icon}
                </Text>

                <Stack direction="horizontal" gap={4} justify="center">
                  <Text variant="caption" weight="bold">
                    {item.high}°
                  </Text>
                  <Text 
                    variant="caption" 
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useId } from 'react';
import {
  Stack,
  Card,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Box,
  Divider,
  Container,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
}

export default function KanbanBoard(props: Props) {
  const { tasks, columns } = props;
  const boardId = useId();

  // Action contract
  const onTaskUpdate = (props as any).onTaskUpdate || (props as any).taskUpdate;

  const [items, setItems] = useState<any[]>([]);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [addingCol, setAddingCol] = useState<string | null>(null);
  const [title, setTitle] = useState('');
  const [prio, setPrio] = useState<'low' | 'medium' | 'high'>('medium');

  useEffect(() => {
    if (tasks && columns) {
      setItems(tasks.map((t, i) => ({
        id: t.id || `${boardId}-t-${i}`,
        title: t.title || 'Task',
        priority: t.priority || 'medium',
        assignee: t.assignee || 'User',
        column: t.column || (columns[0]?.id || 'todo'),
        dueDate: t.dueDate
      })));
    }
  }, [tasks, columns, boardId]);

  const onUpdate = (action: string, id: string | undefined, data: any) => {
    if (onTaskUpdate) onTaskUpdate({ action, taskId: id, data });
  };

  const moveTask = (id: string, col: string) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, column: col } : item));
    onUpdate('move', id, { column: col });
  };

  const editTask = (id: string, newTitle: string) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, title: newTitle } : item));
    onUpdate('edit', id, { title: newTitle });
    setEditingId(null);
  };

  const addTask = (colId: string) => {
    if (!title.trim()) return;
    const task = { id: `${boardId}-${Date.now()}`, title, priority: prio, column: colId, assignee: 'Me' };
    setItems(prev => [...prev, task]);
    onUpdate('add', undefined, task);
    setTitle('');
    setAddingCol(null);
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-4)">
      <Stack gap={24}>
        <Card border padding={16} radius="lg" shadow="sm">
          <Heading level={3}>Project Board</Heading>
        </Card>
        <Box style={{ display: 'grid', gridAutoFlow: 'column', gridAutoColumns: '320px', gap: 'var(--ggui-spacing-4)', overflowX: 'auto', paddingBottom: 16 }}>
          {columns && columns.map((col, idx) => {
            const cid = col.id || `col-${idx}`;
            const cItems = items.filter(t => t.column === cid);
            return (
              <Box key={cid} background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={12} style={{ border: '1px solid var(--ggui-color-outline)', minHeight: '400px', height: 'fit-content' }}>
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between">
                    <Heading level={6}>{col.name}</Heading>
                    <Badge variant="default" size="sm">{cItems.length}</Badge>
                  </Stack>
                  <Stack gap={12}>
                    {cItems.map(item => (
                      <Card key={item.id} padding={12} border shadow="sm" radius="md">
                        <Stack gap={12}>
                          {editingId === item.id ? (
                            <Box>
                              <div style={{ marginBottom: 4 }}>
                                <label htmlFor={`${item.id}-input`} style={{ fontSize: '12px', fontWeight: 600, color: 'var(--ggui-color-onSurfaceVariant)' }}>Edit Task</label>
                              </div>
                              <Input id={`${item.id}-input`} label="Edit Task" value={item.title} onChange={(v) => setItems(prev => prev.map(x => x.id === item.id ? {...x, title: v} : x))} onBlur={() => editTask(item.id, item.title)} autoFocus size="sm" />
                            </Box>
                          ) : (
                            <div onDoubleClick={() => setEditingId(item.id)} style={{ cursor: 'pointer' }}><Text weight="semibold" size="sm">{item.title}</Text></div>
                          )}
                          <Stack direction="horizontal" justify="between" align="center">
                            <Badge variant={item.priority === 'high' ? 'error' : item.priority === 'medium' ? 'warning' : 'info'} size="sm">{item.priority}</Badge>
                            <Box style={{ width: '100px' }}>
                              <Select size="sm" value={item.column} onChange={(v) => moveTask(item.id, v)} options={columns.map(c => ({ label: c.name || '', value: c.id || '' }))} />
                            </Box>
                          </Stack>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                  {addingCol === cid ? (
                    <Card border padding={12} shadow="md">
                      <Stack gap={12}>
                        <Box>
                          <div style={{ marginBottom: 4 }}>
                            <label htmlFor={`${cid}-new-input`} style={{ fontSize: '12px', fontWeight: 600, color: 'var(--ggui-color-onSurfaceVariant)' }}>New Task</label>
                          </div>
                          <Input id={`${cid}-new-input`} label="New Task" value={title} onChange={setTitle} size="sm" autoFocus />
                        </Box>
                        <Select label="Priority" size="sm" value={prio} onChange={(v) => setPrio(v as any)} options={[{label: 'Low', value: 'low'}, {label: 'Med', value: 'medium'}, {label: 'High', value: 'high'}]} />
                        <Button size="sm" fullWidth onClick={() => addTask(cid)}>Add</Button>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="ghost" fullWidth onClick={() => setAddingCol(cid)}>Add Task</Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Card,
  Box,
  Text,
  Heading,
  Input,
  Badge,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

/**
 * Interactive Periodic Table Component
 * Features filtering, detailed view on selection, and responsive grid layout.
 */
export default function PeriodicTable(props: Props) {
  const elements = props.elements || [];
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedSymbol, setSelectedSymbol] = useState('');

  // Filtering logic
  const filtered = useMemo(() => {
    if (!searchQuery) return elements;
    const q = searchQuery.toLowerCase();
    return elements.filter((e) => {
      const nameMatch = (e.name || '').toLowerCase().indexOf(q) !== -1;
      const symbolMatch = (e.symbol || '').toLowerCase().indexOf(q) !== -1;
      return nameMatch || symbolMatch;
    });
  }, [elements, searchQuery]);

  // Selected element data
  const activeElement = useMemo(() => {
    return elements.find((e) => e.symbol === selectedSymbol);
  }, [elements, selectedSymbol]);

  // Style helper based on category
  const getCategoryStyles = (cat?: string) => {
    const c = (cat || '').toLowerCase();
    if (c.includes('noble')) return { bg: 'var(--ggui-color-info-100, #cffafe)', tx: 'var(--ggui-color-info-700, #0e7490)', v: 'info' as const };
    if (c.includes('alkali metal')) return { bg: 'var(--ggui-color-error-100, #fee2e2)', tx: 'var(--ggui-color-error-700, #b91c1c)', v: 'error' as const };
    if (c.includes('alkaline')) return { bg: 'var(--ggui-color-warning-100, #fef3c7)', tx: 'var(--ggui-color-warning-700, #b45309)', v: 'warning' as const };
    if (c.includes('nonmetal')) return { bg: 'var(--ggui-color-success-100, #dcfce7)', tx: 'var(--ggui-color-success-700, #15803d)', v: 'success' as const };
    if (c.includes('transition')) return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', tx: 'var(--ggui-color-primary-700, #0369a1)', v: 'primary' as const };
    if (c.includes('metalloid')) return { bg: 'var(--ggui-color-warning-200, #fde68a)', tx: 'var(--ggui-color-warning-800, #92400e)', v: 'warning' as const };
    return { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', tx: 'var(--ggui-color-neutral-700, #374151)', v: 'secondary' as const };
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Search and Header Section */}
        <Stack direction="horizontal" align="center" justify="between">
          <Box>
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interactive explorer of chemical elements
            </Text>
          </Box>
          <Box style={{ width: '320px' }}>
            <Input
              label="Search Elements"
              placeholder="e.g., Oxygen or O"
              value={searchQuery}
              onChange={(v) => setSearchQuery(v)}
            />
          </Box>
        </Stack>

        {/* Periodic Grid */}
        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(50px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '940px'
            }}
          >
            {elements.map((item) => {
              const styles = getCategoryStyles(item.category);
              const isSelected = selectedSymbol === item.symbol;
              const matchesSearch = filtered.some((f) => f.symbol === item.symbol);

              return (
                <Box
                  key={item.symbol}
                  background={isSelected ? 'var(--ggui-color-primary-100, #e0f2fe)' : styles.bg}
                  borderRadius="var(--ggui-shape-radius-sm, 4px)"
                  padding="var(--ggui-spacing-1, 4px)"
                  style={{
                    gridColumn: item.col,
                    gridRow: item.row,
                    aspectRatio: '1',
                    border: isSelected
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    opacity: matchesSearch ? 1 : 0.2,
                    transition: 'all 0.15s ease-in-out',
                    transform: isSelected ? 'scale(1.05)' : 'none',
                    zIndex: isSelected ? 10 : 1,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none'
                  }}
                  onClick={() => setSelectedSymbol(item.symbol || '')}
                >
                  <Text size="xs" weight="bold" color={styles.tx}>
                    {item.atomicNumber}
                  </Text>
                  <Spacer size="flex" />
                  <Text align="center" weight="bold" size="lg" color={styles.tx}>
                    {item.symbol}
                  </Text>
                  <Spacer size="flex" />
                </Box>
              );
            })}
          </Box>
        </Box>

        {/* Detail Panel */}
        {activeElement ? (
          <Card padding="var(--ggui-spacing-6, 24px)" radius="lg" shadow="md">
            <Stack gap="var(--ggui-spacing-6, 24px)">
              <Stack direction="horizontal" align="center" justify="between">
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-6, 24px)">
                  <Box
                    background={getCategoryStyles(activeElement.category).bg}
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    padding="var(--ggui-spacing-4, 16px)"
                    style={{
                      width: '80px',
                      height: '80px',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      justifyContent: 'center',
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)'
                    }}
                  >
                    <Text variant="caption" weight="bold" color={getCategoryStyles(activeElement.category).tx}>
                      {activeElement.atomicNumber}
                    </Text>
                    <Heading level={2} color={getCategoryStyles(activeElement.category).tx}>
                      {activeElement.symbol}
                    </Heading>
                  </Box>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={1}>{activeElement.name}</Heading>
                    <Badge variant={getCategoryStyles(activeElement.category).v}>
                      {activeElement.category}
                    </Badge>
                  </Stack>
                </Stack>
                <Stack align="end" gap="var(--ggui-spacing-1, 4px)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Atomic Weight
                  </Text>
