import React, { useState, useEffect, useRef } from 'react';
import { 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Badge, 
  Divider, 
  Input, 
  Button, 
  Icon,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface Component
 */
export default function ChatInterface(props: Props) {
  const { title = "Conversation", currentUser = "Me", participantCount, messages = [], onSendMessage } = props;
  const [inputText, setInputText] = useState('');
  const [localMessages, setLocalMessages] = useState(messages);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputId = "chat-input-v9";

  useEffect(() => { setLocalMessages(messages); }, [messages]);

  useEffect(() => {
    const h = (e: any) => { if (e.detail && e.detail.text) setLocalMessages(p => [...p, { sender: e.detail.sender || 'Agent', text: e.detail.text, timestamp: e.detail.timestamp || new Date().toISOString() }]); };
    const g = globalThis as any;
    if (g && g.addEventListener) { g.addEventListener('ggui:agent-data', h); return () => g.removeEventListener('ggui:agent-data', h); }
  }, []);

  useEffect(() => { if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight; }, [localMessages]);

  const onSend = () => {
    if (!inputText.trim()) return;
    const ts = new Date().toISOString();
    if (onSendMessage) onSendMessage({ text: inputText, timestamp: ts });
    setLocalMessages(p => [...p, { sender: currentUser, text: inputText, timestamp: ts }]);
    setInputText('');
  };

  const Lbl = Text as any;

  return (
    <Card padding={0} shadow="md" radius="lg" border style={{ display: 'flex', flexDirection: 'column', height: '600px', width: '100%', backgroundColor: 'var(--ggui-color-surface)' }}>
      <MotionKeyframes />
      <Box paddingX={16} paddingY={12} background="var(--ggui-color-surfaceVariant)">
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={4} color="var(--ggui-color-onSurface)">{title}</Heading>
          {participantCount && <Badge variant="primary" pill>{participantCount} Participants</Badge>}
        </Stack>
      </Box>
      <Divider margin={0} />
      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: '16px', display: 'flex', flexDirection: 'column', background: 'var(--ggui-color-surface)' }}>
        <Stack gap={16}>
          {localMessages.map((m, i) => (
            <Stack key={i} align={m.sender === currentUser ? 'end' : 'start'} gap={4}>
              {!isCons(localMessages, i) && <Text variant="label" size="xs">{m.sender}</Text>}
              <Box paddingX={12} paddingY={8} borderRadius="12px" background={m.sender === currentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'} style={{ maxWidth: '80%', color: m.sender === currentUser ? '#fff' : 'inherit' }}>
                <Text size="sm" color="inherit">{m.text}</Text>
              </Box>
              <Text variant="caption" size="xs">{m.timestamp && new Date(m.timestamp).toLocaleTimeString()}</Text>
            </Stack>
          ))}
        </Stack>
      </div>
      <Divider margin={0} />
      <Box padding={16} background="var(--ggui-color-surface)">
        <Stack gap={4}>
          <Lbl as="label" htmlFor={inputId} variant="label" size="xs">Message</Lbl>
          <Input id={inputId} label="Message" placeholder="Type..." value={inputText} onChange={setInputText} onKeyDown={(e) => e.key === 'Enter' && onSend()} />
        </Stack>
        <Stack direction="horizontal" justify="end" style={{ marginTop: '8px' }}>
          <Button variant="primary" onClick={onSend} disabled={!inputText.trim()}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

function isCons(msgs: any[], i: number) { return i > 0 && msgs[i - 1].sender === msgs[i].sender; }

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Badge,
  Spinner,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: StockData[];
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState<StockData[]>(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState(!props.stocks || props.stocks.length === 0);

  useEffect(() => {
    if (props.stocks) {
      setStocks(props.stocks);
      setIsConnecting(false);
    }
    if (props.lastUpdated) {
      setLastUpdated(props.lastUpdated);
    }

    const handler = (event: any) => {
      const data = event.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
        setIsConnecting(false);
      }
    };

    // Agent data stream listener (as required by prompt)
    const g: any = globalThis;
    if (g.addEventListener) {
      g.addEventListener('ggui:agent-data', handler);
      return () => g.removeEventListener('ggui:agent-data', handler);
    }
  }, [props.stocks, props.lastUpdated]);

  const renderTime = (t?: string) => {
    if (!t) return '--:--:--';
    try {
      return new Date(t).toLocaleTimeString();
    } catch {
      return t;
    }
  };

  if (isConnecting && stocks.length === 0) {
    return (
      <Container padding={64} center>
        <Stack align="center" gap={16}>
          <Spinner size={40} color="var(--ggui-color-primary-600)" />
          <Text variant="bodyLarge" weight="medium">Connecting to Stream...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Stack direction="horizontal" justify="between" align="end" wrap style={{ gap: 'var(--ggui-spacing-4, 16px)' }}>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Real-time Trading Data</Text>
          </Stack>
          <Badge variant="secondary" size="lg" pill={false}>
            Updated: {renderTime(lastUpdated)}
          </Badge>
        </Stack>

        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={24}>
          {stocks.map((stock, i) => {
            const isUp = (stock.change || 0) >= 0;
            const statusColor = isUp ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Box 
                key={`${stock.symbol || 'S'}-${i}`}
                style={{ animation: `ggui-slideInUp 300ms ease-out ${i * 50}ms both` }}
              >
                <Card 
                  padding={24} 
                  shadow="sm"
                  style={{ borderLeft: `4px solid ${statusColor}` }}
                >
                  <Stack gap={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={2}>
                        <Text weight="bold" size="2xl" truncate>{stock.symbol || '---'}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" truncate>
                          {stock.name || '---'}
                        </Text>
                      </Stack>
                      <Text weight="bold" size="xl">${(stock.price || 0).toFixed(2)}</Text>
                    </Stack>

                    <Stack direction="horizontal" align="center" gap={8}>
                      <Badge variant={isUp ? 'success' : 'error'} size="md">
                        <Stack direction="horizontal" align="center" gap={4}>
                          <span>{isUp ? '▲' : '▼'}</span>
                          <span>{Math.abs(stock.changePercent || 0).toFixed(2)}%</span>
                        </Stack>
                      </Badge>
                      <Text size="sm" weight="medium" color={statusColor}>
                        {isUp ? '+' : ''}{(stock.change || 0).toFixed(2)}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </CardGrid>

        {!isConnecting && stocks.length === 0 && (
          <Box padding={48} borderRadius={12} background="var(--ggui-color-surfaceVariant)" style={{ textAlign: 'center' }}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">No active tickers found</Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

/**
 * __GGUI_META__
 * {
 *   "category": "Dashboard",
 *   "description": "Stock dashboard with real-time reactive updates and grid-based responsive layout."
 * }
 */

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Spacer,
  Divider,
  Box,
  Icon
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called when user completes onboarding */
  complete: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

/**
 * GeneratedComponent: A 3-step onboarding wizard.
 * Handles profile setup, user preferences, and final review before submission.
 */
export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions = [], roleOptions = [], complete } = props;

  // --- Step Navigation State ---
  const [currentStep, setCurrentStep] = useState(1);

  // --- Form Data State ---
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions.length > 0 ? avatarOptions[0] : ''),
    role: initialProfile.role || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  // --- Helpers & Validation ---
  const isEmailValid = (e: string) => /\S+@\S+\.\S+/.test(e);
  const isStep1Valid = formData.name.trim() !== '' && isEmailValid(formData.email) && formData.avatar !== '';
  const isStep2Valid = formData.role !== '';

  const updateField = (key: string, value: any) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  };

  const handleNext = () => {
    if (currentStep < 3) setCurrentStep((prev) => prev + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep((prev) => prev - 1);
  };

  const handleFinish = () => {
    complete(formData);
  };

  // --- UI Layouts for Steps ---
  const stepLabel = currentStep === 1 ? 'Profile Setup' : currentStep === 2 ? 'Preferences' : 'Review & Confirm';

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-12, 48px) var(--ggui-spacing-4, 16px)">
      <Stack gap={24}>
        {/* Progress Header */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">
              STEP {currentStep} OF 3
            </Text>
            <Text variant="label" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
              {stepLabel}
            </Text>
          </Stack>
          <Progress value={(currentStep / 3) * 100} size="sm" variant="default" />
        </Stack>

        <Card padding={24} shadow="md" radius="xl" border>
          <div style={{ animation: 'ggui-fadeIn 200ms ease-out', minHeight: '340px' }} key={currentStep}>
            {/* STEP 1: Profile Setup */}
            {currentStep === 1 && (
              <Stack gap={20}>
                <Heading level={2}>Account Profile</Heading>

                <Input
                  label="Name"
                  placeholder="e.g. Jane Doe"
                  value={formData.name}
                  onChange={(val) => updateField('name', val)}
                  required
                />

                <Input
                  label="Email"
                  type="email"
                  placeholder="name@example.com"
                  value={formData.email}
                  onChange={(val) => updateField('email', val)}
                  required
                  error={formData.email && !isEmailValid(formData.email) ? 'Invalid email format' : undefined}
                />

                <Stack gap={8}>
                  <Text variant="label" weight="medium">Pick an Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map((a) => (
                      <button
                        key={a}
                        type="button"
                        aria-label={`Select avatar ${a}`}
                        onClick={() => updateField('avatar', a)}
                        style={{
                          fontSize: '24px',
                          width: 52,
                          height: 52,
                          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          background: formData.avatar === a ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
                          border: `2px solid ${formData.avatar === a ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                          cursor: 'pointer',
                          transition: 'all 0.15s ease-in-out',
                          outline: 'none'
                        }}
                      >
                        {a}
                      </button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* STEP 2: Preferences */}
            {currentStep === 2 && (
              <Stack gap={20}>
                <Heading level={2}>Preferences</Heading>

                <Select
                  label="Primary Role"
                  placeholder="Select your role"
                  value={formData.role}
                  onChange={(val) => updateField('role', val)}
                  options={roleOptions.map(r => ({ value: r, label: r }))}
                  required
                />

                <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                <Stack gap={20}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack gap={2}>
                      <Text variant="label">Notifications</Text>
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Get email updates about your projects</Text>
                    </Stack>
                    <Toggle 
                      checked={formData.emailNotifications} 
                      onChange={(v) => updateField('emailNotifications', v)} 
                      label="Notifications"
                    />
                  </Stack>

                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack gap={2}>
                      <Text variant="label">Dark Mode</Text>
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Use a darker theme for the interface</Text>
                    </Stack>
                    <Toggle 
                      checked={formData.theme === 'dark'} 
                      onChange={(v) => updateField('theme', v ? 'dark' : 'light')} 
                      label="Dark Theme"
                    />
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* STEP 3: Review & Summary */}
            {currentStep === 3 && (
              <Stack gap={20}>
                <Heading level={2}>Review Details</Heading>

                <Box padding={20} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={16}>
                  <Stack gap={16}>
                    <Stack direction="horizontal" gap={16} align="center">
                      <div 
                        style={{ 
                          fontSize: '32px', 
                          background: 'var(--ggui-color-surface, #fafafa)', 
                          width: 64, 
                          height: 64, 
                          borderRadius: '50%', 
                          display: 'flex', 
                          alignItems: 'center', 
                          justifyContent: 'center', 
                          border: '1px solid var(--ggui-color-outline, #d4d4d8)' 
                        }}
                      >
                        {formData.avatar}
                      </div>
                      <Stack gap={2}>
                        <Text variant="bodyLarge" weight="bold">{formData.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{formData.email}</Text>
                      </Stack>
                    </Stack>

                    <Divider color="var(--ggui-color-outline, #d4d4d8)" margin={4} />

                    <Stack gap={12}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">ROLE</Text>
                        <Text variant="bodySmall" weight="semibold">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">NOTIFICATIONS</Text>
                        <Text variant="bodySmall" weight="semibold">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">THEME</Text>
                        <Text variant="bodySmall" weight="semibold" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
                <Text variant="bodySmall" align="center" color="var(--ggui-color-neutral-500, #6b7280)">
                  Click complete to finish your onboarding process.
                </Text>
              </Stack>
            )}
          </div>

          <Spacer size={24} />

          {/* Action Footer */}
          <Stack direction="horizontal" gap={12} justify={currentStep === 1 ? 'end' : 'between'}>
            {currentStep > 1 && (
              <Button 
                variant="ghost" 
                onClick={handleBack} 
                leftIcon={<Icon name="chevron-left" size={16} />}
              >
                Go Back
              </Button>
            )}

            {currentStep < 3 ? (
              <Button 
                variant="primary" 
                disabled={currentStep === 1 ? !isStep1Valid : !isStep2Valid} 
                onClick={handleNext}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Continue
              </Button>
            ) : (
              <Button variant="primary" onClick={handleFinish}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

