/**
 * WeatherCard Component
 *
 * A visually clean weather dashboard displaying current conditions and a multi-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 58 },
    { day: 'Tue', icon: '☁️', high: 68, low: 55 },
    { day: 'Wed', icon: '🌧️', high: 62, low: 50 },
