    { day: 'Fri', icon: '☀️', high: 74, low: 57 },
  ],
}: Props) {
  // Simple emoji mapper for better presentation if needed
  const getWeatherEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud') || c.includes('overcast')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle') || c.includes('shower')) return '🌧️';
    if (c.includes('snow') || c.includes('ice')) return '❄️';
    if (c.includes('thunder') || c.includes('storm')) return '⛈️';
    if (c.includes('mist') || c.includes('fog') || c.includes('haze')) return '🌫️';
    return '⛅'; // Default part cloudy
  };

  const currentEmoji = condition.length <= 2 ? condition : getWeatherEmoji(condition);

  return (
    <Card shadow="md" padding={24} radius="xl">
      <Stack gap={24}>
        {/* Header Section: City and Date */}
        <Stack direction="horizontal" justify="between" align="start">
