          </Stack>
          <Box
            padding={12}
            borderRadius="var(--ggui-shape-radius-full)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
          >
            <div style={{ fontSize: '2rem', lineHeight: 1 }}>{currentEmoji}</div>
          </Box>
        </Stack>

        {/* Main Temperature Section */}
        <Stack direction="horizontal" align="start" gap={8}>
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-onSurface)"
            style={{ lineHeight: 1, letterSpacing: 'var(--ggui-font-letterSpacing-tight)' }}
          >
            {Math.round(temperature)}
          </Text>
          <Text
            size="2xl"
            weight="medium"
            color="var(--ggui-color-primary-600)"
            style={{ marginTop: 'var(--ggui-spacing-1)' }}
          >
            °{unit}
          </Text>
          <Spacer size="flex" />
          <Stack align="end" gap={0}>
            <Text weight="semibold" color="var(--ggui-color-onSurface)">
              {condition}
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Feels like {Math.round(temperature - 2)}°
            </Text>
          </Stack>
        </Stack>

        {/* Details Row: Humidity and Wind Speed */}
        <Box
          padding={16}
          borderRadius="var(--ggui-shape-radius-lg)"
          background="var(--ggui-color-surfaceVariant)"
        >
          <Stack direction="horizontal" justify="around" align="center">
