import React, { useState } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Box,
  Divider,
  Icon,
  Spacer
} from '@ggui-ai/design/primitives';

type Task = { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
type Column = { id?: string; name?: string };

interface Props {
  /** Array of tasks */
  tasks: Task[];
  /** Column definitions */
  columns: Column[];
  /** Task update callback */
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    tasks = [], 
    columns = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' }
    ],
    onTaskUpdate 
  } = props;

  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);

  const handleCreate = (columnId: string) => {
    if (!newTitle.trim()) { setFormError('Required'); return; }
    setIsSubmitting(true);
    setTimeout(() => {
      onTaskUpdate?.({ action: 'create', data: { id: String(Date.now()), title: newTitle, priority: newPriority, column: columnId } });
      setNewTitle('');
      setAddingToColumn(null);
      setIsSubmitting(false);
    }, 500);
  };

  const handleMove = (taskId: string, columnId: string) => {
    onTaskUpdate?.({ action: 'move', taskId, data: { column: columnId } });
  };

  const handleEdit = (taskId: string, title: string) => {
    onTaskUpdate?.({ action: 'edit', taskId, data: { title } });
    setEditingTaskId(null);
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Statistics Banner */}
        <Card padding="var(--ggui-spacing-4, 16px)" shadow="sm" radius="lg" border>
          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="center">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Total Tasks</Text>
                <Heading level={4} color="var(--ggui-color-onSurface)">{tasks.length}</Heading>
              </Stack>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2, 8px)" />
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Done</Text>
                <Heading level={4} color="var(--ggui-color-onSurface)">{tasks.filter(t => t.column === 'done').length}</Heading>
              </Stack>
            </Stack>
            <Badge variant="primary" size="lg">Kanban Overview</Badge>
          </Stack>
        </Card>

        {/* Board Columns */}
        <Box style={{ display: 'flex', gap: 'var(--ggui-spacing-6, 24px)', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          {columns.map((col, idx) => (
            <Box key={col.id || idx} style={{ flex: '0 0 320px', minWidth: '320px' }}>
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack direction="horizontal" justify="between" align="center">
                  <Heading level={5} color="var(--ggui-color-onSurface)">{col.name}</Heading>
                  <Badge variant="secondary" size="sm">{tasks.filter(t => t.column === col.id).length}</Badge>
                </Stack>

                <Stack gap="var(--ggui-spacing-3, 12px)">
                  {tasks.filter(t => t.column === col.id).map(task => (
                    <Card key={task.id} padding="var(--ggui-spacing-4, 16px)" border radius="md" shadow="sm">
                      <Stack gap="var(--ggui-spacing-3, 12px)">
                        <Stack direction="horizontal" justify="between" align="start">
                          <Box style={{ flex: 1 }}>
                            {editingTaskId === task.id ? (
                              <Input label="Title" value={task.title} onChange={(v) => handleEdit(task.id!, v)} autoFocus size="sm" />
                            ) : (
                              <div onDoubleClick={() => setEditingTaskId(task.id!)} style={{ cursor: 'pointer' }}>
                                <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface)">{task.title}</Text>
                              </div>
                            )}
                          </Box>
                          <Button variant="ghost" size="xs" onPress={() => setEditingTaskId(task.id!)} aria-label="Edit task">
                            <Icon name="settings" size={14} />
                          </Button>
                        </Stack>

                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'} size="sm">{task.priority?.toUpperCase()}</Badge>
                          <Avatar name={task.assignee} size="sm" />
                        </Stack>

                        <Divider margin="var(--ggui-spacing-1, 4px)" />

                        <Select label="Move task" size="sm" value={task.column} onChange={(v) => handleMove(task.id!, v)} options={columns.map(c => ({ label: String(c.name), value: String(c.id) }))} />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingToColumn === col.id ? (
                  <Card padding="var(--ggui-spacing-4, 16px)" border shadow="md">
                    <Stack gap="var(--ggui-spacing-4, 16px)">
                      <Input label="New Task Title" placeholder="What to do?" value={newTitle} onChange={setNewTitle} error={formError || undefined} />
                      <Select label="Priority" value={newPriority} onChange={(v) => setNewPriority(v as any)} options={[{label:'Low', value:'low'},{label:'Medium', value:'medium'},{label:'High', value:'high'}]} />
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                        <Button variant="primary" size="sm" fullWidth loading={isSubmitting} onPress={() => handleCreate(col.id!)}>Submit</Button>
                        <Button variant="ghost" size="sm" onPress={() => setAddingToColumn(null)}>Cancel</Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="ghost" size="sm" fullWidth leftIcon={<Icon name="plus" size={16} />} onPress={() => setAddingToColumn(col.id!)} style={{ border: '1px dashed var(--ggui-color-outline)' }}>Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Box,
  Heading,
  Badge,
  Divider,
  Button
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const getCategoryColor = (category: string = '') => {
  const cat = category.toLowerCase();
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-100, #f3f4f6)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info-100, #cffafe)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-info-200, #a5f3fc)';
  if (cat.includes('actinide')) return 'var(--ggui-color-error-200, #fecaca)';
  return 'var(--ggui-color-neutral-50, #f9fafb)';
};

const getBadgeVariant = (category: string = ''): 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' => {
  const cat = category.toLowerCase();
  if (cat.includes('alkali metal')) return 'error';
  if (cat.includes('alkaline earth')) return 'warning';
  if (cat.includes('transition metal')) return 'primary';
  if (cat.includes('post-transition')) return 'secondary';
  if (cat.includes('metalloid')) return 'info';
  if (cat.includes('nonmetal')) return 'success';
  if (cat.includes('noble gas')) return 'info';
  if (cat.includes('lanthanide')) return 'info';
  if (cat.includes('actinide')) return 'error';
  return 'default';
};

const CATEGORIES = [
  'Alkali metal',
  'Alkaline earth metal',
  'Transition metal',
  'Post-transition metal',
  'Metalloid',
  'Reactive nonmetal',
  'Noble gas',
  'Lanthanide',
  'Actinide'
];

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const isVisible = (el: ElementData) => {
    if (!search) return true;
    const query = search.toLowerCase();
    return el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" align="center" justify="between" wrap gap="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>The Periodic Table</Heading>
            <Text color="var(--ggui-color-onSurfaceVariant)">Interactive Element Browser</Text>
          </Stack>
          <Box style={{ flex: '0 1 20rem' }}>
            <SearchField
              value={search}
              onChange={setSearch}
              placeholder="Search elements..."
              size="md"
            />
          </Box>
        </Stack>

        {/* Periodic Table Grid */}
        <Box 
          style={{ 
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
          }}
        >
          {elements.map((el) => {
            const active = isVisible(el);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

            return (
              <button
                key={el.atomicNumber}
                onClick={() => setSelectedElement(el)}
                aria-label={`${el.name} (${el.symbol})`}
                style={{
                  gridColumn: el.col,
                  gridRow: el.row,
                  aspectRatio: '1/1',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  cursor: 'pointer',
                  position: 'relative',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  backgroundColor: getCategoryColor(el.category),
                  border: isSelected 
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                    : '1px solid var(--ggui-color-outline, #d4d4d8)',
                  opacity: active ? 1 : 0.15,
                  transition: 'all 200ms cubic-bezier(0, 0, 0.2, 1)',
                  transform: isSelected ? 'scale(1.1)' : 'none',
                  zIndex: isSelected ? 10 : 1,
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  outline: 'none'
                }}
              >
                <Text 
                  size="xs" 
                  weight="bold"
                  style={{ 
                    position: 'absolute', 
                    top: '0.1rem', 
                    left: '0.1rem', 
                    lineHeight: 1,
                    fontSize: '0.6rem',
                    pointerEvents: 'none'
                  }}
                >
                  {el.atomicNumber}
                </Text>

                <Text weight="bold" size="lg" style={{ lineHeight: 1, pointerEvents: 'none' }}>
                  {el.symbol}
                </Text>
              </button>
            );
          })}
        </Box>

        {/* Legend */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap justify="center">
          {CATEGORIES.map(cat => (
            <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Box 
                style={{ 
                  width: 'var(--ggui-spacing-4, 16px)', 
                  height: 'var(--ggui-spacing-4, 16px)', 
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)', 
                  backgroundColor: getCategoryColor(cat),
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)' 
                }}
              />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>

        {/* Detail View */}
        {selectedElement ? (
          <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" radius="xl">
            <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="start" wrap>
              {/* Element Visualizer */}
              <Box 
                style={{ 
                  minWidth: '8rem', 
                  display: 'flex', 
                  flexDirection: 'column', 
                  alignItems: 'center',
                  padding: 'var(--ggui-spacing-8, 32px)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  backgroundColor: getCategoryColor(selectedElement.category),
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)'
                }}
              >
                <Text size="xl" color="var(--ggui-color-onSurfaceVariant)">{selectedElement.atomicNumber}</Text>
                <Heading level={1}>{selectedElement.symbol}</Heading>
                <Text weight="medium">{selectedElement.name}</Text>
