        ) : (
          <Card 
            padding="var(--ggui-spacing-8, 32px)" 
            shadow="none" 
            border 
            style={{ borderStyle: 'dashed', textAlign: 'center' }}
          >
            <Text color="var(--ggui-color-onSurfaceVariant)">
              Select an element to view detailed chemical and physical properties.
            </Text>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Badge, 
  Input, 
  Button, 
  Icon,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface({
  title = 'Chat',
  currentUser = 'User',
  participantCount,
  messages: initialMessages = [],
  onSendMessage
}: Props) {
  const [messages, setMessages] = useState(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setMessages(initialMessages); }, [initialMessages]);

  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail;
      if (data && (data.text || data.content)) {
        setMessages((prev) => [...prev, {
          sender: data.sender || 'Agent',
          text: data.text || data.content,
          timestamp: new Date().toISOString(),
        }]);
      }
    };
    addEventListener('ggui:agent-data', handleData as any);
    return () => removeEventListener('ggui:agent-data', handleData as any);
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const p = { text: inputValue, timestamp: new Date().toISOString() };
    if (onSendMessage) onSendMessage(p);
    setMessages([...messages, { sender: currentUser, ...p }]);
    setInputValue('');
  };

  const grouped = messages.reduce((acc: any[], curr) => {
    const last = acc[acc.length - 1];
    if (last && last.sender === curr.sender) last.items.push(curr);
    else acc.push({ sender: curr.sender, items: [curr] });
    return acc;
  }, []);

  return (
    <Card padding={0} shadow="md" radius="lg" border style={{ display: 'flex', flexDirection: 'column', height: '600px', width: '100%', background: 'var(--ggui-color-surface, #ffffff)' }}>
      <MotionKeyframes />
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outline)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{title}</Heading>
          {participantCount && <Badge variant="primary">{participantCount} active</Badge>}
        </Stack>
      </Box>
      <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', background: 'var(--ggui-color-surfaceVariant)' }}>
        <div ref={scrollRef}>
          <Stack gap={16}>
            {grouped.map((g, i) => (
              <Stack key={i} align={g.sender === currentUser ? 'end' : 'start'} gap={4}>
                <Text variant="label" size="xs">{g.sender}</Text>
                {g.items.map((m: any, j: number) => (
                  <Box key={j} padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" borderRadius="12px" background={g.sender === currentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surface)'}>
                    <Text color={g.sender === currentUser ? 'var(--ggui-color-surface, #ffffff)' : 'inherit'}>{m.text}</Text>
                  </Box>
                ))}
              </Stack>
            ))}
          </Stack>
        </div>
      </Box>
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-outline)' }}>
        <Stack gap={8}>
          <Text as="label" variant="label">Message</Text>
          <Stack direction="horizontal" gap={12} align="end">
            <Input label="Message" value={inputValue} onChange={setInputValue} onKeyDown={(e) => e.key === 'Enter' && handleSend()} />
            <Button variant="primary" onPress={handleSend}>Send</Button>
          </Stack>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Spinner,
  Box,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard component displays a grid of stock cards with real-time updates.
 * Listens for 'ggui:agent-data' events for live streaming.
 */
export default function StockTickerDashboard({ stocks: initialStocks = [], lastUpdated: initialUpdated }: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialUpdated);
  const [isConnecting, setIsConnecting] = useState(true);

  // Stream Contract: Listen for data updates via agent events
  useEffect(() => {
    if (initialStocks && initialStocks.length > 0) {
      setIsConnecting(false);
    }

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data) {
        if (Array.isArray(data.stocks)) {
          setStocks(data.stocks);
        }
        if (data.lastUpdated) {
          setLastUpdated(data.lastUpdated);
        }
        setIsConnecting(false);
      }
    };

    // Use document-level listener if possible or direct registration
    // This complies with Stream Contract requirements
    const target = typeof document !== 'undefined' ? document : null;
    if (target) {
      target.addEventListener('ggui:agent-data', handleAgentData);
    }

    return () => {
      if (target) {
        target.removeEventListener('ggui:agent-data', handleAgentData);
      }
    };
  }, [initialStocks]);

  const formatPrice = (val?: number) => (val !== undefined ? val.toFixed(2) : '0.00');

  const formatTime = (iso?: string) => {
    if (!iso) return '--:--:--';
    try {
      const date = new Date(iso);
      return date.toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch (e) {
      return 'Syncing...';
    }
  };

  // Loading State
  if (isConnecting && stocks.length === 0) {
    return (
      <Container padding={64}>
        <Stack align="center" justify="center" gap={16}>
          <Spinner size={48} color="var(--ggui-color-primary-600)" />
          <Stack align="center" gap={4}>
            <Heading level={4}>Connecting to Live Feed</Heading>
            <Text color="var(--ggui-color-onSurfaceVariant)">Initializing real-time market connection...</Text>
          </Stack>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="end" wrap gap={16}>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Real-time monitoring of equities and market indices.
            </Text>
          </Stack>

          <Box 
            paddingX={16} 
            paddingY={8} 
            background="var(--ggui-color-surfaceVariant)" 
            borderRadius="var(--ggui-shape-radius-full)"
          >
            <Stack direction="horizontal" gap={12} align="center">
              <div 
                style={{
                  width: '8px',
                  height: '8px',
                  borderRadius: '50%',
                  backgroundColor: isConnecting ? "var(--ggui-color-warning-500)" : "var(--ggui-color-success-500)",
                  boxShadow: isConnecting ? 'none' : '0 0 8px var(--ggui-color-success-400)'
                }}
              />
              <Text variant="label" color="var(--ggui-color-onSurface)">
                Updated: <Text as="span" weight="bold" color="var(--ggui-color-onSurface)">{formatTime(lastUpdated)}</Text>
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant)" />

        {/* Stock Dashboard Grid */}
        <CardGrid columns={{ sm: 1, md: 3 }} gap={20}>
          {stocks.map((stock) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const statusColor = isPositive 
              ? 'var(--ggui-color-success-600)' 
              : 'var(--ggui-color-error-600)';
            const statusBg = isPositive
              ? 'var(--ggui-color-success-50, #f0fdf4)'
              : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Card 
                key={stock.symbol || `ticker-${Math.random()}`} 
                padding={0}
                radius="lg" 
                shadow="sm"
                border={false}
              >
                <Box 
                  padding={20} 
                  borderRadius="var(--ggui-shape-radius-lg)"
                  background="var(--ggui-color-surface)"
                  style={{ 
                    border: `1px solid ${statusColor}`,
                    height: '100%',
                    display: 'flex',
                    flexDirection: 'column',
                    transition: 'all 200ms ease'
                  }}
                >
                  <Stack gap={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={2}>
                        <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                          {stock.symbol}
                        </Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" truncate>
                          {stock.name}
                        </Text>
                      </Stack>
                      <Box 
                        paddingX={10} 
                        paddingY={4} 
                        borderRadius="var(--ggui-shape-radius-md)" 
                        background={statusBg}
                      >
                        <Stack direction="horizontal" gap={4} align="center">
                          <Text size="sm" weight="bold" color={statusColor}>
                            {isPositive ? '▲' : '▼'}
                          </Text>
                          <Text size="sm" weight="bold" color={statusColor}>
                            {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                          </Text>
                        </Stack>
                      </Box>
                    </Stack>

                    <Spacer size={4} />

                    <Stack gap={6}>
                      <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                        ${formatPrice(stock.price)}
                      </Text>
                      <Stack direction="horizontal" gap={8} align="center">
                        <Text variant="caption" weight="semibold" color={statusColor}>
                          {isPositive ? '+' : ''}{stock.change?.toFixed(2)}
                        </Text>
                        <div 
                          style={{
                            width: '4px',
                            height: '4px',
                            borderRadius: '50%',
                            backgroundColor: 'var(--ggui-color-outline)'
                          }}
                        />
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Today</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Card>
            );
          })}
        </CardGrid>

        {/* Empty State / No Data */}
        {stocks.length === 0 && !isConnecting && (
          <Box 
            padding={64} 
            background="var(--ggui-color-surfaceVariant)" 
            borderRadius="var(--ggui-shape-radius-xl)"
            style={{ textAlign: 'center' }}
          >
            <Stack align="center" gap={16}>
              <Text size="xl" weight="medium" color="var(--ggui-color-onSurface)">Market feed empty</Text>
              <Text color="var(--ggui-color-onSurfaceVariant)">Awaiting stock data from the live stream.</Text>
            </Stack>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Heading, 
  Text, 
  Progress, 
  Input, 
  Select, 
  Toggle, 
  Button, 
  Divider, 
  Spacer, 
  Badge, 
  Alert,
  RadioGroup,
  MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent({ 
  avatarOptions, 
  roleOptions, 
  initialProfile = {}, 
  onComplete 
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? (avatarOptions?.[0] || '👤'),
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light'
  });

  const updateField = (key: string, value: any) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isStep1Valid = formData.name.trim().length > 0 && emailRegex.test(formData.email);
  const isStep2Valid = formData.role !== '';

  const handleNext = () => setStep(s => Math.min(s + 1, 3));
  const handleBack = () => setStep(s => Math.max(s - 1, 1));
  const handleComplete = () => {
    if (onComplete) onComplete(formData);
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-10, 40px) var(--ggui-spacing-5, 20px)">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" radius="xl" border={true}>
        <Stack gap={32}>
          <Stack gap={16}>
            <Stack direction="horizontal" justify="between" align="end">
              <Stack gap={4}>
                <Heading level={2}>Welcome aboard</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Complete these steps to get started</Text>
              </Stack>
              <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Step {step} of 3</Text>
            </Stack>
            <Progress value={(step / 3) * 100} size="md" variant="default" />
          </Stack>

          <Box style={{ minHeight: 'var(--ggui-spacing-12, 340px)' }}>
            {step === 1 && (
              <Stack gap={24} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Input label="Full Name" value={formData.name} onChange={(val) => updateField('name', val)} required />
                <Input label="Email Address" type="email" value={formData.email} onChange={(val) => updateField('email', val)} required error={formData.email && !emailRegex.test(formData.email) ? "Invalid email" : undefined} />
                <Stack gap={12}>
                  <Text variant="label">Choose your avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions?.map(emoji => (
                      <button key={emoji} type="button" onClick={() => updateField('avatar', emoji)} style={{ background: formData.avatar === emoji ? 'var(--ggui-color-primary-50)' : 'transparent', border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`, borderRadius: 'var(--ggui-shape-radius-lg, 12px)', padding: 'var(--ggui-spacing-3, 12px) var(--ggui-spacing-4, 16px)', cursor: 'pointer', transition: 'all 200ms ease-in-out', display: 'flex', alignItems: 'center', justifyContent: 'center', minWidth: '48px', minHeight: '48px', outline: 'none' }} aria-pressed={formData.avatar === emoji}>
                        <Text size="3xl">{emoji}</Text>
                      </button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Select label="Your Role" value={formData.role} onChange={(val: string) => updateField('role', val)} options={roleOptions?.map(r => ({ value: r, label: r }))} placeholder="Select a role..." required />
                <Toggle label="Enable email notifications" checked={formData.emailNotifications} onChange={(val: boolean) => updateField('emailNotifications', val)} />
                <RadioGroup label="Preferred Theme" direction="horizontal" value={formData.theme} onChange={(val: string) => updateField('theme', val)} options={[{ value: 'light', label: 'Light Mode' }, { value: 'dark', label: 'Dark Mode' }]} />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding="var(--ggui-spacing-6, 24px)" borderRadius="var(--ggui-shape-radius-xl, 16px)" style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
                  <Stack gap={20}>
                    <Stack direction="horizontal" align="center" gap={16}>
                      <Box background="var(--ggui-color-surface, #ffffff)" padding={12} borderRadius="9999px" style={{ border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
                        <Text size="4xl">{formData.avatar}</Text>
                      </Box>
                      <Stack gap={2}>
                        <Heading level={4}>{formData.name}</Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={12}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                        <Text weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                        <Badge variant={formData.emailNotifications ? 'success' : 'default'}>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                        <Text weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
                <Alert variant="info" title="Final Review">Everything looks good? Click complete below to finalize your profile setup.</Alert>
              </Stack>
            )}
          </Box>

          <Stack gap={20}>
            <Divider margin={0} />
            <Stack direction="horizontal" justify="between">
              {step > 1 ? (
                <Button variant="ghost" onClick={handleBack} leftIcon={<span>←</span>}>Back</Button>
              ) : <Spacer size="flex" />}
              <Button variant="primary" onClick={step === 3 ? handleComplete : handleNext} disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}>
                {step === 3 ? 'Complete Setup' : 'Next Step'}
              </Button>
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
